/**
 * backend-50/js/app.js
 * Security hardened, ARIA-compliant, no inline handlers.
 */
'use strict';


const Q = [{ "id": 1, "cat": "Node.js", "tech": ["Node.js"], "diff": "Easy", "q": "What is Node.js and what makes it different from PHP or Java on the server?", "a": "<strong>Node.js</strong> is a JavaScript runtime built on Chrome's V8 engine that lets you run JavaScript on the server. The core difference is its <strong>non-blocking, event-driven I/O model</strong>.<br><br>PHP and Java traditionally use a <em>thread-per-request</em> model — each incoming request gets its own thread, which blocks while waiting for I/O (database, file, network). Under heavy load threads get exhausted and requests queue up.<br><br>Node.js uses a <strong>single thread with an event loop</strong>. Instead of blocking on I/O, it starts the operation, moves on to the next request, and handles the result via a callback or Promise when the operation completes.", "code": "// PHP-style blocking (pseudocode):\n$user = db_query('SELECT * FROM users WHERE id = 1'); // BLOCKS\necho $user['name'];\n\n// Node.js non-blocking:\ndb.query('SELECT * FROM users WHERE id = 1', (err, user) => {\n  console.log(user.name); // runs when query completes\n});\nconsole.log('This runs immediately!'); // doesn't wait for DB", "explain": "\"Node.js is single-threaded but highly concurrent — like one efficient chef juggling many orders at once instead of one chef per customer. I use it when I need high concurrency with I/O-heavy workloads like REST APIs or real-time chat. For CPU-heavy tasks like video encoding, I would reach for Python or Java instead.\"", "tip": "Node.js is not ideal for CPU-intensive tasks — heavy computation blocks the single event loop thread, starving all other requests. Use worker threads or offload CPU-bound work to a separate service." },
{ "id": 2, "cat": "REST API", "tech": ["API", "REST"], "diff": "Easy", "q": "What is a REST API and what are its core principles?", "a": "<strong>REST</strong> (Representational State Transfer) is an architectural style for designing networked APIs using HTTP to perform CRUD operations on resources identified by URLs.<br><br>The six core principles:<br><strong>Stateless</strong>: Each request contains all information needed — the server stores no client session state between requests.<br><strong>Client-Server</strong>: UI and business logic are separated.<br><strong>Cacheable</strong>: Responses must define themselves as cacheable or not.<br><strong>Uniform Interface</strong>: Consistent URLs, HTTP verbs, and response formats.<br><strong>Layered System</strong>: Client does not know if it is talking to the end server or an intermediary.<br><strong>Code on Demand</strong> (optional): Server can send executable code to clients.", "code": "// RESTful URL conventions:\n// GET    /api/users         list all users\n// GET    /api/users/:id     get one user\n// POST   /api/users         create a user\n// PUT    /api/users/:id     replace a user fully\n// PATCH  /api/users/:id     update specific fields\n// DELETE /api/users/:id     delete a user\n\n// HTTP Status Codes:\n// 200 OK, 201 Created, 204 No Content\n// 400 Bad Request, 401 Unauthorized, 403 Forbidden\n// 404 Not Found, 500 Internal Server Error", "explain": "\"REST is about treating everything as a resource with a URL. The stateless principle is what makes REST APIs scalable — every request must be self-contained, carrying auth tokens and everything needed. This lets you scale horizontally by adding more servers without shared session state.\"", "tip": "Resources should be nouns, not verbs: /users not /getUsers, /orders not /createOrder. HTTP methods are the verbs. This makes your API intuitive to any developer without reading documentation." },
{ "id": 3, "cat": "CRUD", "tech": ["API", "REST"], "diff": "Easy", "q": "What is CRUD and how does it map to HTTP methods and SQL operations?", "a": "<strong>CRUD</strong> stands for Create, Read, Update, Delete — the four fundamental operations of any persistent storage system. In REST APIs and SQL databases, these map to specific HTTP methods and SQL commands.", "code": "// CRUD -> HTTP -> SQL:\n// Create -> POST   -> INSERT\n// Read   -> GET    -> SELECT\n// Update -> PUT/PATCH -> UPDATE\n// Delete -> DELETE -> DELETE\n\napp.post('/users',       createUser);\napp.get('/users',        getAllUsers);\napp.get('/users/:id',    getOneUser);\napp.put('/users/:id',    replaceUser);\napp.patch('/users/:id',  updateUser);\napp.delete('/users/:id', deleteUser);\n\n// SQL equivalents:\n// INSERT INTO users (name, email) VALUES (?, ?);\n// SELECT * FROM users WHERE id = ?;\n// UPDATE users SET name = ? WHERE id = ?;\n// DELETE FROM users WHERE id = ?;", "explain": "\"CRUD is the vocabulary of every application. User signup = INSERT. View profile = SELECT. Change password = UPDATE. Delete account = DELETE. I always clarify PUT vs PATCH: PUT replaces the entire resource (send all fields), PATCH updates only specific fields (send only what changed). In practice, PATCH is more useful for most APIs.\"", "tip": "In REST, PUT should be idempotent — calling it multiple times with the same data produces the same result. POST is not idempotent — calling it twice creates two resources. This distinction matters for retry logic in distributed systems and mobile apps with unreliable networks." },
{ "id": 4, "cat": "MySQL", "tech": ["MySQL"], "diff": "Easy", "q": "What are SQL indexes and how do they improve query performance?", "a": "An <strong>index</strong> is a B-tree data structure MySQL maintains alongside a table to speed up row retrieval. Without an index, MySQL performs a full table scan — reading every single row (O(n)). With an index on the queried column, MySQL jumps directly to relevant rows (O(log n)).<br><br>MySQL automatically creates indexes for <code>PRIMARY KEY</code> and <code>UNIQUE</code> columns. You add manual indexes on columns frequently used in <code>WHERE</code>, <code>JOIN ON</code>, and <code>ORDER BY</code> clauses.<br><br><strong>Trade-off</strong>: indexes speed up reads (SELECT) but slow down writes (INSERT, UPDATE, DELETE) because the index B-tree must be updated on every write.", "code": "-- Check if a query uses an index\nEXPLAIN SELECT * FROM orders WHERE user_id = 42;\n-- type: ALL = full scan (bad on large tables)\n-- type: ref  = index used (good)\n\n-- Create an index\nCREATE INDEX idx_user_id ON orders(user_id);\n\n-- Composite index (equality columns FIRST, range LAST)\nCREATE INDEX idx_status_date ON orders(status, created_at);\n-- Useful for: WHERE status = 'paid' ORDER BY created_at\n\n-- View existing indexes\nSHOW INDEX FROM orders;", "explain": "\"I always run EXPLAIN before adding an index. The type column tells the story: ALL means MySQL reads every row — a red flag on large tables. ref or range means an index is used efficiently. I once added a single index on orders.user_id and a 3-second query dropped to 12ms. But I never index blindly — every extra index slows down writes.\"", "tip": "MySQL cannot use an index if you wrap the column in a function: WHERE YEAR(created_at) = 2024 forces a full table scan. WHERE created_at >= '2024-01-01' uses the index. Always write range conditions directly on the column, never inside a function call." },
{ "id": 5, "cat": "MongoDB", "tech": ["MongoDB"], "diff": "Easy", "q": "What is MongoDB and how does it differ from a relational database like MySQL?", "a": "<strong>MongoDB</strong> is a document-oriented NoSQL database that stores data as BSON (Binary JSON) documents in collections. Unlike SQL's rigid tables, MongoDB is schema-flexible — documents in the same collection can have completely different structures.<br><br>Key differences:<br><strong>Documents vs Rows</strong>: MongoDB stores nested objects and arrays natively; SQL requires multiple tables and JOINs.<br><strong>Schema</strong>: MongoDB is schema-flexible by default. SQL requires columns defined before data is inserted.<br><strong>Joins</strong>: SQL uses powerful JOINs; MongoDB typically embeds related data or uses $lookup.<br><strong>Scaling</strong>: MongoDB was designed for horizontal sharding across many servers.", "code": "// MongoDB document -- embeds all related data naturally\n{\n  _id: ObjectId('64a1b2c3...'),\n  name: 'Alice',\n  email: 'alice@x.com',\n  address: { city: 'Mumbai', pin: '400001' },\n  orders: [\n    { id: 'ORD-1', total: 299, status: 'paid' },\n    { id: 'ORD-2', total: 149, status: 'pending' }\n  ]\n}\n// One query gets everything -- no JOIN needed", "explain": "\"MongoDB is excellent for data that is naturally hierarchical or changes structure frequently. The biggest mental shift from SQL: model data around how you will query it, not around normalized relationships. If you always read a user with their recent orders, embed those orders directly in the user document.\"", "tip": "MongoDB added multi-document ACID transactions in v4.0. However, transactions in MongoDB are slower than single-document operations — design your schema to avoid needing them by embedding related data whenever possible." },
{ "id": 6, "cat": "PHP", "tech": ["PHP"], "diff": "Easy", "q": "What is PHP and what are its main use cases in modern backend development?", "a": "<strong>PHP</strong> (PHP: Hypertext Preprocessor) is a server-side scripting language designed for web development. It runs on the server, generates HTML or JSON, and sends it to the client. PHP powers approximately 77% of all websites with a known server-side language — including WordPress, and historically Facebook and Wikipedia.<br><br>Modern PHP (8.x) includes typed properties, enums, fibers (async), match expressions, and named arguments — it is a significantly different language from the PHP of a decade ago.<br><br>Main use cases: REST APIs, content management systems, e-commerce platforms (WooCommerce, Magento), and server-side HTML rendering.", "code": "<?php\ndeclare(strict_types=1);\n\nfunction getUserById(int $id): ?array\n{\n    $db   = new PDO('mysql:host=localhost;dbname=app', $user, $pass);\n    $stmt = $db->prepare('SELECT * FROM users WHERE id = ?');\n    $stmt->execute([$id]);\n    return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;\n}\n\n// Match expression (PHP 8.0+)\n$label = match($status) {\n    'active'   => 'User is active',\n    'inactive' => 'User is inactive',\n    default    => 'Unknown status',\n};\n\necho json_encode(['user' => getUserById(1)]);", "explain": "\"Modern PHP 8 with typed properties and named arguments is a genuinely good language. Laravel consistently ranks as one of the best developer experiences in backend development. Its Eloquent ORM, queue system, and ecosystem rival Node.js frameworks in productivity.\"", "tip": "Always use PDO with prepared statements for database queries — never concatenate user input into SQL strings. That is how SQL injection happens. For APIs, use JWT or token-based auth instead of PHP sessions, which are file-based and hard to scale horizontally." },
{ "id": 7, "cat": "Python", "tech": ["Python"], "diff": "Easy", "q": "What makes Python popular for backend development and what frameworks are commonly used?", "a": "Python's popularity in backend development comes from its readability, massive ecosystem, and natural strength in data science and ML — making it the obvious choice when your backend needs machine learning capabilities.<br><br>Popular Python backend frameworks:<br><strong>Django</strong>: Full-featured, batteries-included. ORM, admin panel, auth, migrations built-in. Best for complex, content-heavy applications.<br><strong>FastAPI</strong>: Modern, async-first, auto-generates OpenAPI docs, uses Python type hints for validation. Best for high-performance APIs in 2026.<br><strong>Flask</strong>: Minimal and flexible micro-framework. Best for small APIs or microservices.<br><strong>Celery</strong>: Distributed task queue for background jobs, commonly paired with Django or Flask.", "code": "# FastAPI -- modern Python API (trending in 2026)\nfrom fastapi import FastAPI, HTTPException\nfrom pydantic import BaseModel\nfrom typing import Optional\n\napp = FastAPI()\n\nclass User(BaseModel):       # Pydantic validates request body automatically\n    name:  str\n    email: str\n    age:   Optional[int] = None\n\n@app.get('/users/{user_id}')\nasync def get_user(user_id: int):\n    user = await db.fetch_one('SELECT * FROM users WHERE id = :id', {'id': user_id})\n    if not user:\n        raise HTTPException(status_code=404, detail='Not found')\n    return user\n\n@app.post('/users', status_code=201)\nasync def create_user(user: User):  # Pydantic auto-validates\n    new_id = await db.execute('INSERT INTO users...', user.dict())\n    return {'id': new_id, **user.dict()}", "explain": "\"FastAPI is my go-to for new Python APIs in 2026. It is async-native, automatically validates requests using Pydantic models, generates interactive OpenAPI docs, and benchmarks faster than Flask and Django REST Framework. Django is still excellent when you need its batteries — admin panel, ORM, permissions system.\"", "tip": "Python's GIL prevents true multi-threading for CPU-bound tasks in CPython. For CPU-heavy work use multiprocessing. For I/O-bound async tasks, which is most web API work, asyncio and FastAPI work excellently and perform competitively with Node.js." },
{ "id": 8, "cat": "Server Management", "tech": ["Linux", "Server"], "diff": "Easy", "q": "What is a reverse proxy and why is Nginx used in front of Node.js or Python backends?", "a": "A <strong>reverse proxy</strong> is a server that sits between clients and your backend application servers. Clients send all requests to the reverse proxy, which forwards them to the appropriate backend server and returns the response.<br><br>Why use Nginx as a reverse proxy in front of your app:<br><strong>SSL termination</strong>: Nginx handles HTTPS so backend apps run plain HTTP internally.<br><strong>Static file serving</strong>: Nginx serves static assets much faster than Node.js.<br><strong>Load balancing</strong>: Distributes requests across multiple backend instances.<br><strong>Security</strong>: Hides backend server details, can rate-limit and block malicious requests.<br><strong>Caching</strong>: Can cache responses to reduce backend load.", "code": "# Nginx reverse proxy config for a Node.js app\nserver {\n    listen 443 ssl;\n    server_name myapp.com;\n\n    ssl_certificate     /etc/letsencrypt/live/myapp.com/fullchain.pem;\n    ssl_certificate_key /etc/letsencrypt/live/myapp.com/privkey.pem;\n\n    # Forward API requests to Node.js on port 3000\n    location /api {\n        proxy_pass http://localhost:3000;\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n    }\n\n    # Serve static frontend build directly (faster!)\n    location / {\n        root /var/www/myapp/dist;\n        try_files $uri $uri/ /index.html;\n    }\n}", "explain": "\"In every production deployment I set up, Nginx sits in front of everything. It handles SSL via Let Encrypt for free, serves the React build directly without touching Node, and proxies API calls to PM2-managed Node processes. Static files at Nginx speed, and Node only handles what it needs to.\"", "tip": "Never expose your Node.js or Python app port (3000, 8080) directly to the internet. Always put Nginx in front. Use UFW to allow only ports 80 and 443 publicly, and restrict SSH (port 22) to your specific IP address." },
{ "id": 9, "cat": "Webhooks", "tech": ["Webhooks", "Node.js"], "diff": "Easy", "q": "What is a webhook and how does it differ from a regular API call?", "a": "A <strong>webhook</strong> is an HTTP callback — your server exposes an endpoint, and an external service hits it automatically when a specific event occurs. It is the 'don't call us, we'll call you' pattern.<br><br><strong>Regular API call (polling)</strong>: Your app repeatedly asks 'did anything happen?' — wastes requests and introduces latency even when nothing has changed.<br><strong>Webhook (event push)</strong>: The external service sends a POST request to your endpoint the moment an event fires — real-time, no wasted requests.<br><br>Real-world uses: Stripe posts when a payment succeeds; GitHub posts when someone pushes code; Twilio posts when an SMS is received.", "code": "// Express.js webhook endpoint for Stripe\napp.post('/webhooks/stripe',\n  express.raw({ type: 'application/json' }),  // raw body needed for signature\n  async (req, res) => {\n    const sig = req.headers['stripe-signature'];\n\n    let event;\n    try {\n      event = stripe.webhooks.constructEvent(\n        req.body, sig, process.env.STRIPE_WEBHOOK_SECRET\n      );\n    } catch (err) {\n      return res.status(400).send('Invalid signature');\n    }\n\n    if (event.type === 'payment_intent.succeeded') {\n      await fulfillOrder(event.data.object);\n    }\n\n    res.json({ received: true });  // respond quickly!\n  }\n);", "explain": "\"Webhooks are fundamentally more efficient than polling. Instead of asking every 5 seconds, Stripe tells me the exact moment a payment succeeds. Three things I always implement: signature verification (proves the request is genuine), idempotency (store event IDs to prevent duplicate processing on retries), and quick acknowledgement — respond 200 immediately and queue any heavy work.\"", "tip": "Always respond to webhook events within 5-10 seconds or the sender will retry. If your processing takes longer, acknowledge with 200 OK immediately and queue the actual work using a job queue like Bull or BullMQ." },
{ "id": 10, "cat": "TTL", "tech": ["Redis", "Databases"], "diff": "Easy", "q": "What is TTL (Time To Live) and where is it used in backend systems?", "a": "<strong>TTL (Time To Live)</strong> is a value that specifies how long a piece of data should live before it is automatically expired or deleted. It is a fundamental concept that appears across caching, authentication, DNS, and database design.<br><br>Where TTL is used:<br><strong>Redis cache</strong>: Set TTL on cached values so they auto-expire and get re-fetched fresh from the database.<br><strong>MongoDB TTL index</strong>: Automatically deletes documents after a specified time — perfect for OTP codes, sessions, temporary data.<br><strong>JWT tokens</strong>: The <code>exp</code> claim defines when a token expires — effectively a TTL.<br><strong>DNS records</strong>: How long DNS resolvers cache a record before re-querying.<br><strong>HTTP Cache-Control</strong>: <code>max-age</code> sets how long browsers cache a response.", "code": "// Redis: set a key with a 10-minute TTL\nawait client.setEx('user:42', 600, JSON.stringify(userData));\nconst ttl = await client.ttl('user:42'); // seconds remaining\n\n// MongoDB: TTL index -- auto-delete OTP codes after 10 minutes\notpSchema.index(\n  { createdAt: 1 },\n  { expireAfterSeconds: 600 }  // MongoDB removes expired docs automatically\n);\n\n// JWT with TTL\nconst token = jwt.sign(\n  { userId: 42, role: 'user' },\n  process.env.JWT_SECRET,\n  { expiresIn: '15m' }  // TTL = 15 minutes\n);\n\n// HTTP Cache-Control\nres.setHeader('Cache-Control', 'public, max-age=3600'); // 1 hour", "explain": "\"TTL appears everywhere in backend systems. I use it most in Redis caching — set a TTL so cached data auto-expires rather than serving stale data forever. For OTP codes or password reset tokens, MongoDB TTL indexes are elegant — the database automatically cleans up expired codes without needing a separate cron job.\"", "tip": "In Redis, if you set a key without a TTL it lives forever until manually deleted or evicted by memory pressure. Always set explicit TTLs on cached data. Configure Redis with maxmemory-policy allkeys-lru so it evicts least-recently-used keys when memory is full, rather than refusing writes." },
{ "id": 11, "cat": "PostgreSQL", "tech": ["PostgreSQL"], "diff": "Easy", "q": "What makes PostgreSQL different from MySQL and when would you choose it?", "a": "Both are excellent open-source relational databases, but PostgreSQL is considered more feature-rich and fully standards-compliant.<br><br>Key PostgreSQL advantages:<br><strong>Full ACID compliance</strong>: Built-in from the ground up. MySQL's ACID support historically varied by storage engine (InnoDB is ACID, MyISAM is not).<br><strong>Advanced data types</strong>: JSONB (indexed, queryable JSON), Arrays, UUID, geometric types, full-text search natively built in.<br><strong>Window functions and CTEs</strong>: More powerful analytics queries.<br><strong>Partial and expression indexes</strong>: More flexible indexing strategies.", "code": "-- PostgreSQL JSONB -- query inside JSON with full index support\nCREATE TABLE products (\n  id      SERIAL PRIMARY KEY,\n  name    TEXT NOT NULL,\n  details JSONB           -- indexed, queryable JSON column\n);\n\n-- Create GIN index for fast JSONB queries\nCREATE INDEX idx_details ON products USING GIN(details);\n\n-- Query inside JSON -- uses the index!\nSELECT * FROM products WHERE details @> '{\"color\": \"red\"}';\n\n-- Window function: running total per user\nSELECT user_id, amount,\n  SUM(amount) OVER (PARTITION BY user_id ORDER BY created_at) AS running_total\nFROM orders;", "explain": "\"I choose PostgreSQL for new projects whenever I anticipate complex queries, need to store JSON data alongside relational data, or where data integrity is critical. Its JSONB type means it can even replace MongoDB for many use cases. For Supabase, AWS RDS, or any modern cloud deployment, I default to PostgreSQL.\"", "tip": "PostgreSQL's VACUUM process reclaims storage from deleted and updated rows (MVCC). Autovacuum handles this automatically, but for write-heavy tables you may need to tune autovacuum settings to prevent table bloat and performance degradation." },
{ "id": 12, "cat": "Java", "tech": ["Java"], "diff": "Easy", "q": "What is Java and why is it widely used for enterprise backend development?", "a": "<strong>Java</strong> is a statically-typed, object-oriented language that runs on the JVM (Java Virtual Machine). The JVM makes Java code platform-independent — write once, run anywhere. Java powers critical systems at Google, Amazon, Netflix, LinkedIn, and most banks.<br><br>Why Java dominates enterprise backend:<br><strong>Performance</strong>: JVM JIT compilation produces highly optimized native code that rivals C++ for long-running server workloads.<br><strong>Ecosystem</strong>: Spring Framework, Hibernate ORM, Maven/Gradle, an enormous library ecosystem.<br><strong>Type safety</strong>: Compile-time errors catch bugs before deployment.<br><strong>Concurrency</strong>: Rich threading model and java.util.concurrent library.", "code": "// Spring Boot REST API -- most common enterprise Java setup\n@RestController\n@RequestMapping(\"/api/users\")\npublic class UserController {\n\n    @Autowired\n    private UserService userService;\n\n    @GetMapping(\"/{id}\")\n    public ResponseEntity&lt;User&gt; getUser(@PathVariable Long id) {\n        return userService.findById(id)\n            .map(ResponseEntity::ok)\n            .orElse(ResponseEntity.notFound().build());\n    }\n\n    @PostMapping\n    public ResponseEntity&lt;User&gt; createUser(@Valid @RequestBody UserDTO dto) {\n        User created = userService.create(dto);\n        URI location = URI.create(\"/api/users/\" + created.getId());\n        return ResponseEntity.created(location).body(created);\n    }\n}", "explain": "\"Java's verbosity pays off in large teams — the explicit types and structure make code easier to understand six months later. Spring Boot makes Java rapid to develop with — a full REST API with database, validation, and auth takes minutes to scaffold. For backend roles at banks, telecoms, or large enterprises, Java with Spring Boot is almost always the expected stack.\"", "tip": "Java 17+ (LTS) introduced significant improvements: records for immutable data classes, sealed classes, text blocks, and pattern matching. Modern Java is considerably less verbose than Java 8. Target Java 17+ idioms in interviews — interviewers at modern companies will expect them." },
{ "id": 13, "cat": "C / C++", "tech": ["C", "C++"], "diff": "Easy", "q": "What is the difference between C and C++ and when would you use each in backend or systems development?", "a": "<strong>C</strong> is a low-level procedural language from 1972 that directly manipulates memory through pointers and compiles to native machine code. The Linux kernel, PostgreSQL, MySQL, SQLite, Nginx, Apache, and Chrome's V8 engine are all written in C or C++.<br><br><strong>C++</strong> adds object-oriented programming, templates, the STL (Standard Template Library), and RAII (automatic resource management via smart pointers) on top of C, while retaining C's performance.<br><br>Key additions in C++ over C:<br><strong>Classes and OOP</strong>: Encapsulation, inheritance, polymorphism.<br><strong>STL</strong>: Ready-to-use vectors, maps, sets, algorithms.<br><strong>Smart pointers</strong>: unique_ptr, shared_ptr — eliminate manual malloc/free.", "code": "// C -- manual memory, maximum control\ntypedef struct { int id; char name[100]; } User;\n\nUser* create_user(int id, const char* name) {\n    User* u = (User*)malloc(sizeof(User));\n    if (!u) return NULL;          // always check!\n    u->id = id;\n    strncpy(u->name, name, 99);\n    return u;\n}\n// Caller MUST call free(u) -- no garbage collector!\n\n// C++ -- RAII, zero-overhead abstractions\n#include &lt;memory&gt;\nstruct User { int id; std::string name; };\n\nauto user = std::make_unique&lt;User&gt;(1, \"Alice\");\n// Auto-freed when unique_ptr goes out of scope -- no leak!", "explain": "\"C is the bedrock of computing. Understanding C gives you intuition for why garbage-collected languages have pauses, why buffer overflows are security vulnerabilities, and how data structures actually work in memory. C++ adds modern safety features (smart pointers, RAII) while keeping C performance. For game engines (Unreal Engine), high-frequency trading, and performance-critical services, C++ is the language of choice.\"", "tip": "In modern C++, avoid raw new and delete entirely. Use make_unique and make_shared for heap allocation — they ensure memory is freed automatically when the smart pointer goes out of scope (RAII). This eliminates most memory leaks without any garbage collector overhead." },
{ "id": 14, "cat": "NestJS", "tech": ["NestJS", "Node.js"], "diff": "Easy", "q": "What is NestJS and why has it become popular for enterprise Node.js backends?", "a": "<strong>NestJS</strong> is a progressive Node.js framework built on top of Express (or optionally Fastify), using TypeScript by default. Its architecture is heavily inspired by Angular — it uses decorators, dependency injection, and a module system that enforces structure in large codebases.<br><br>Why teams choose NestJS:<br><strong>TypeScript first</strong>: Full TypeScript support out of the box.<br><strong>Decorators</strong>: @Controller, @Get, @Injectable make code declarative and self-documenting.<br><strong>Dependency injection</strong>: Built-in IoC container for testable, loosely coupled code.<br><strong>Opinionated structure</strong>: Forces organization into modules, controllers, and services — essential in large teams.", "code": "// NestJS -- structured, decorator-driven architecture\n@Injectable()\nexport class UsersService {\n  constructor(@InjectRepository(User) private repo: Repository&lt;User&gt;) {}\n\n  findAll() { return this.repo.find(); }\n  findOne(id: number) { return this.repo.findOneBy({ id }); }\n  create(dto: CreateUserDto) {\n    const user = this.repo.create(dto);\n    return this.repo.save(user);\n  }\n}\n\n@Controller('users')\n@UseGuards(JwtAuthGuard)\nexport class UsersController {\n  constructor(private readonly usersService: UsersService) {}\n\n  @Get()       findAll()                        { return this.usersService.findAll(); }\n  @Get(':id')  findOne(@Param('id') id: string) { return this.usersService.findOne(+id); }\n  @Post()      create(@Body() dto: CreateUserDto){ return this.usersService.create(dto); }\n}", "explain": "\"NestJS is what I recommend when a team is building a large Node.js API that needs to stay maintainable as it grows. Plain Express gives you total freedom, which becomes a curse in large codebases — everyone structures code differently. NestJS enforces consistency. The dependency injection makes unit testing clean — mock the repository, inject it, test the service in isolation.\"", "tip": "NestJS works on top of Express by default, so all Express middleware is compatible. You can swap the underlying adapter from Express to Fastify with one config change for approximately 20% better throughput on high-traffic APIs — no other code changes needed." },
{ "id": 15, "cat": "Databases", "tech": ["MySQL", "PostgreSQL"], "diff": "Easy", "q": "What are database transactions and what does ACID mean?", "a": "A <strong>transaction</strong> is a sequence of SQL operations executed as a single atomic unit — either all operations succeed or all of them fail and are reversed. Transactions are critical for operations where partial success would corrupt data, like bank transfers or order processing.<br><br><strong>ACID</strong> properties guarantee reliable transactions:<br><strong>Atomicity</strong>: All operations succeed, or none do. No partial updates ever reach the database.<br><strong>Consistency</strong>: The transaction brings the database from one valid state to another, respecting all constraints.<br><strong>Isolation</strong>: Concurrent transactions don't interfere with each other — each sees a consistent snapshot.<br><strong>Durability</strong>: Once committed, the data survives crashes. Written to disk via WAL (Write-Ahead Log).", "code": "-- Transfer $500 from account 1 to account 2\nBEGIN;\n  UPDATE accounts SET balance = balance - 500 WHERE id = 1;\n  UPDATE accounts SET balance = balance + 500 WHERE id = 2;\nCOMMIT;   -- both succeed: write to disk\n-- ROLLBACK; -- something failed: undo everything\n\n-- Node.js with pg (PostgreSQL)\nconst client = await pool.connect();\ntry {\n  await client.query('BEGIN');\n  await client.query(\n    'UPDATE accounts SET balance = balance - $1 WHERE id = $2', [500, fromId]\n  );\n  await client.query(\n    'UPDATE accounts SET balance = balance + $1 WHERE id = $2', [500, toId]\n  );\n  await client.query('COMMIT');\n} catch (e) {\n  await client.query('ROLLBACK');\n  throw e;\n} finally {\n  client.release(); // ALWAYS return connection to pool!\n}", "explain": "\"The bank transfer is the textbook ACID example. If we debit account A but the server crashes before crediting account B, money disappears from the system. ROLLBACK ensures the debit is undone as if it never happened. Keep transactions short — a transaction holds locks on affected rows, and long-running transactions cause other queries to queue up, degrading performance under concurrent load.\"", "tip": "MySQL's InnoDB engine supports full ACID transactions; MyISAM does not — never use MyISAM for tables that need transactional safety. Also always call client.release() in a finally block. A connection that is never released back to the pool eventually causes pool exhaustion, where the app hangs waiting for a connection that will never become available." },
{ "id": 16, "cat": "Webpack", "tech": ["Webpack"], "diff": "Easy", "q": "What is Webpack and how is it relevant in backend and fullstack build pipelines?", "a": "<strong>Webpack</strong> is a module bundler — it takes source files with their dependencies and outputs optimized bundles. While primarily known for frontend, Webpack and similar tools (esbuild, Rollup) are used in backend contexts for TypeScript compilation, bundling serverless functions, and optimizing Node.js deployments.<br><br>For fullstack development, Webpack builds the frontend assets (React, CSS, images) that the backend serves as static files. For serverless (AWS Lambda, Cloudflare Workers), bundling is essential because deployment size limits are strict and cold start times are proportional to bundle size.<br><br>Key concepts: <strong>entry</strong> (start of the dependency graph), <strong>output</strong> (bundled file), <strong>loaders</strong> (transform files — ts-loader, babel-loader), <strong>plugins</strong> (build-level operations), <strong>tree shaking</strong> (remove unused code).", "code": "// webpack.config.js for an AWS Lambda (TypeScript)\nconst path = require('path');\n\nmodule.exports = {\n  target: 'node',            // don't bundle Node built-ins\n  mode:   'production',\n  entry:  './src/handler.ts',\n  output: {\n    path:          path.resolve(__dirname, 'dist'),\n    filename:      'handler.js',\n    libraryTarget: 'commonjs2'  // required for Lambda\n  },\n  module: {\n    rules: [{\n      test:    /\\.ts$/,\n      use:     'ts-loader',\n      exclude: /node_modules/\n    }]\n  },\n  // Don't bundle AWS SDK -- already in Lambda runtime\n  externals: { '@aws-sdk/client-s3': 'commonjs @aws-sdk/client-s3' },\n  optimization: { minimize: true }  // smaller bundle = faster cold start\n};", "explain": "\"In backend contexts I use Webpack or esbuild primarily for serverless deployments. AWS Lambda has a 50MB compressed deployment limit, and cold start time scales with bundle size. Bundling a Lambda with TypeScript, stripping unused code via tree shaking, and minifying can reduce a 50MB node_modules deployment to a 2MB bundle — dramatically faster cold starts.\"", "tip": "For backend TypeScript projects, esbuild is 10-100x faster than Webpack with ts-loader because it skips type checking. Use ts-node for local development, esbuild for production builds, and tsc --noEmit separately for type checking in CI. This gives you the fastest possible build times without sacrificing type safety." },
{ "id": 17, "cat": "Server Management", "tech": ["Linux", "DevOps"], "diff": "Easy", "q": "What is Docker and why is it used in modern backend deployments?", "a": "<strong>Docker</strong> is a platform for packaging applications and their dependencies into <strong>containers</strong> — lightweight, isolated runtime environments. A container includes the application, its runtime, libraries, and all configuration, running identically on any machine that has Docker installed.<br><br>Why Docker transformed backend deployments:<br><strong>Consistency</strong>: Eliminates 'it works on my machine' — the container runs identically in dev, staging, and production.<br><strong>Isolation</strong>: Each service runs in its own container with no dependency conflicts.<br><strong>Portability</strong>: Build once, deploy anywhere — local laptop, AWS, GCP, or Azure.<br><strong>Fast startup</strong>: Containers start in milliseconds, enabling rapid horizontal scaling.", "code": "# Dockerfile for a Node.js API\nFROM node:20-alpine\nWORKDIR /app\n# Copy package files FIRST (Docker layer caching!)\nCOPY package*.json ./\nRUN npm ci --omit=dev\n# Copy source code after dependencies\nCOPY . .\nEXPOSE 3000\nCMD [\"node\", \"dist/index.js\"]\n\n---\n# docker-compose.yml -- run entire stack locally\nservices:\n  api:\n    build: .\n    ports: ['3000:3000']\n    environment:\n      DATABASE_URL: postgresql://postgres:pass@db:5432/myapp\n    depends_on: [db, redis]\n  db:\n    image: postgres:16\n    environment: { POSTGRES_PASSWORD: pass }\n  redis:\n    image: redis:7-alpine", "explain": "\"Docker solved the classic problem of code that works locally but breaks in production due to different Node versions, OS libraries, or config. With Docker, you ship the entire environment. In production I run Docker with Compose for multi-service setups, or Kubernetes for large-scale orchestration.\"", "tip": "Copy package.json before copying source code in your Dockerfile. Docker caches each instruction as a layer. If package.json has not changed, Docker reuses the npm install cache layer and the build completes in seconds instead of minutes. Putting COPY . . first invalidates the npm install cache on every single code change." },
{ "id": 18, "cat": "REST API", "tech": ["API"], "diff": "Easy", "q": "What is API authentication and what are the most common methods?", "a": "<strong>API authentication</strong> verifies that the caller is who they claim to be. Different methods suit different use cases:<br><br><strong>API Keys</strong>: A static secret token sent in headers or query params. Simple but cannot expire easily. Best for server-to-server calls.<br><br><strong>JWT (JSON Web Token)</strong>: A signed, self-contained token that encodes the user's identity and claims. Stateless — the server validates the signature without looking up a session. Industry standard for user auth in REST APIs.<br><br><strong>OAuth 2.0</strong>: An authorization framework for third-party access (Login with Google, GitHub). OpenID Connect (OIDC) adds the authentication layer on top.<br><br><strong>Basic Auth</strong>: Base64-encoded username:password in the Authorization header. Only acceptable over HTTPS. Avoid for production APIs.", "code": "// Issue a JWT token on login:\napp.post('/auth/login', async (req, res) => {\n  const user = await validateCredentials(req.body);\n  const token = jwt.sign(\n    { id: user.id, email: user.email, role: user.role },\n    process.env.JWT_SECRET,\n    { expiresIn: '15m' }  // short-lived!\n  );\n  res.json({ token });\n});\n\n// Middleware to verify JWT on every protected request:\nconst verifyToken = (req, res, next) => {\n  const token = req.headers.authorization?.replace('Bearer ', '');\n  if (!token) return res.sendStatus(401);\n  try {\n    req.user = jwt.verify(token, process.env.JWT_SECRET);\n    next();\n  } catch {\n    res.status(403).json({ error: 'Invalid or expired token' });\n  }\n};\n\napp.get('/api/profile', verifyToken, (req, res) => {\n  res.json(req.user); // decoded from token -- no DB lookup!\n});", "explain": "\"For most user-facing REST APIs, JWT is the go-to. JWTs are not encrypted by default — just signed. Anyone can decode the payload with base64. So never put sensitive data like passwords in the payload. The signature just proves the token was issued by you and has not been tampered with. In production I use RS256 (asymmetric) — a private key signs, a public key verifies — so multiple services can verify tokens without sharing the private key.\"", "tip": "Never store JWTs in localStorage — it is vulnerable to XSS attacks. Any injected script can steal the token. Store them in HttpOnly cookies which JavaScript cannot read at all. Pair short-lived access tokens (15 min) with long-lived refresh tokens (7 days) — if an access token is stolen, it expires quickly." },
{ "id": 19, "cat": "Server Management", "tech": ["Linux"], "diff": "Easy", "q": "What are the essential Linux commands every backend developer needs to know?", "a": "As a backend developer deploying and maintaining Linux servers, these commands are used daily:<br><br><strong>File system</strong>: ls, cd, pwd, mkdir, rm, cp, mv, find, cat, less, tail<br><strong>Permissions</strong>: chmod, chown<br><strong>Process management</strong>: ps, kill, top, htop, lsof<br><strong>Networking</strong>: curl, wget, netstat, ping, ssh<br><strong>Text processing</strong>: grep, sed, awk, sort, wc<br><strong>Package management</strong>: apt/apt-get (Debian/Ubuntu), yum/dnf (RHEL/CentOS)", "code": "# Process management\nps aux | grep node    # find Node processes\nlsof -i :3000         # what is using port 3000?\nkill 1234             # graceful shutdown (SIGTERM)\nkill -9 1234          # force kill (use as last resort)\n\n# Log watching -- essential for debugging production\ntail -f /var/log/nginx/error.log  # live feed\ngrep -r 'ERROR' ./logs/           # search for errors\ngrep -n 'userId' src/*.ts         # find with line numbers\n\n# File permissions\nchmod 755 script.sh    # rwxr-xr-x\nchmod 600 .env         # rw------- (owner only)\nchmod +x deploy.sh     # make executable\n\n# SSH key-based auth setup\nssh-keygen -t ed25519 -C 'you@email.com'\nssh-copy-id user@server-ip  # copy public key to server", "explain": "\"When something goes wrong in production, log files are your crime scene. tail -f gives a live feed of log files — one of my most-used commands. lsof -i :3000 is invaluable when a Node server won't start because something else is already using the port — it immediately shows you what process to kill. chmod 600 on .env files is a security fundamental.\"", "tip": "Tab completion in the terminal is your best friend — start typing and press Tab. Ctrl+C kills the running process, Ctrl+L clears the screen, !! reruns the last command, and history shows all previous commands. Learn these early — they save hours every week." },
{ "id": 20, "cat": "Integration", "tech": ["API"], "diff": "Easy", "q": "What is CORS and how do you handle it in a backend API?", "a": "<strong>CORS (Cross-Origin Resource Sharing)</strong> is a browser security mechanism that blocks web pages from making requests to a different origin (protocol + domain + port) than the page itself. The browser enforces this — not the server.<br><br>For example: a React app at <code>localhost:3000</code> making a fetch to <code>localhost:5000/api</code> will be blocked because different ports constitute different origins. The backend must return <code>Access-Control-Allow-Origin</code> headers to explicitly opt in.<br><br>CORS is purely a browser enforcement — curl and Postman do not enforce it, which is why API calls that fail in the browser often succeed in Postman.", "code": "// Express with cors npm package (recommended)\nimport cors from 'cors';\n\n// Development: allow all origins\napp.use(cors());\n\n// Production: whitelist specific origins only\napp.use(cors({\n  origin:         ['https://myapp.com', 'https://www.myapp.com'],\n  methods:        ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],\n  allowedHeaders: ['Content-Type', 'Authorization'],\n  credentials:    true, // required for cookies and auth headers\n}));\n\n// Handle preflight OPTIONS request manually:\napp.use((req, res, next) => {\n  res.setHeader('Access-Control-Allow-Origin', 'https://myapp.com');\n  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,PUT,DELETE');\n  if (req.method === 'OPTIONS') return res.sendStatus(204);\n  next();\n});", "explain": "\"CORS is purely a browser enforcement — curl and Postman never trigger it. In production I always whitelist specific origins, never wildcard * when credentials are involved. The cors npm package handles the fiddly preflight OPTIONS responses automatically.\"", "tip": "When credentials: true is set in your cors config, the frontend fetch must also include credentials: 'include'. Both sides must explicitly opt in. Also, credentials: true cannot be combined with origin: '*' — you must specify explicit allowed origins, which is the right approach for production anyway." },
{ "id": 21, "cat": "Node.js", "tech": ["Node.js"], "diff": "Medium", "q": "What are Node.js streams and when should you use them?", "a": "<strong>Streams</strong> in Node.js let you read or write data piece by piece (in chunks) rather than loading everything into memory at once. They are the foundation of Node's I/O model.<br><br>Four stream types: <strong>Readable</strong> (data source — file read, HTTP request body), <strong>Writable</strong> (data destination — file write, HTTP response), <strong>Duplex</strong> (both — TCP socket), <strong>Transform</strong> (duplex that transforms data as it passes through — gzip compression, encryption).<br><br>Use streams when: processing large files (CSV imports, log files, video), handling file uploads, building download endpoints for large data exports, or piping data through multiple transformation steps.", "code": "const fs   = require('fs');\nconst zlib = require('zlib');\nconst { pipeline } = require('stream/promises');\n\n// Compress a large file -- only ONE chunk in memory at a time!\nasync function compressFile(inputPath, outputPath) {\n  await pipeline(\n    fs.createReadStream(inputPath),   // Readable\n    zlib.createGzip(),                 // Transform\n    fs.createWriteStream(outputPath)   // Writable\n  );\n  // Memory usage: constant, regardless of file size\n}\n\n// Express: stream a large CSV data export\napp.get('/export/users', (req, res) => {\n  res.setHeader('Content-Type', 'text/csv');\n  res.setHeader('Content-Disposition', 'attachment; filename=users.csv');\n  const dbStream = db.queryStream('SELECT * FROM users');\n  dbStream\n    .pipe(csvStringifier)  // Transform: rows to CSV text\n    .pipe(res);             // Writable: HTTP response\n  // User starts downloading immediately, before all data is fetched\n});", "explain": "\"Streams are the Node.js answer to memory efficiency for large data. Without them, processing a 2GB CSV file would require loading all 2GB into RAM, likely crashing the server. With streams, you process one chunk at a time — memory usage stays constant regardless of how large the file is. I always use the pipeline() utility instead of manual .pipe() because pipeline automatically handles errors and cleans up all streams in the chain if any step fails.\"", "tip": "Always use stream.pipeline() instead of .pipe() in production. .pipe() does not automatically destroy streams on error, which causes memory and resource leaks. pipeline() handles cleanup and error propagation automatically throughout the entire chain." },
{ "id": 22, "cat": "MySQL", "tech": ["MySQL", "PostgreSQL"], "diff": "Medium", "q": "What are database isolation levels and the concurrency anomalies they prevent?", "a": "<strong>Isolation levels</strong> control how concurrent transactions see each other's uncommitted changes. Higher isolation means fewer anomalies but worse performance due to more locking.<br><br><strong>Concurrency anomalies</strong>:<br>- <strong>Dirty Read</strong>: Reading another transaction's uncommitted data that may be rolled back.<br>- <strong>Non-repeatable Read</strong>: Reading the same row twice within one transaction gets different values because another transaction committed between reads.<br>- <strong>Phantom Read</strong>: A query returns different rows on second execution because another transaction inserted or deleted matching rows.<br><br><strong>Isolation levels from weakest to strongest</strong>:<br>- <strong>READ UNCOMMITTED</strong>: Allows all anomalies. Almost never used.<br>- <strong>READ COMMITTED</strong>: Prevents dirty reads. Default in PostgreSQL.<br>- <strong>REPEATABLE READ</strong>: Prevents dirty reads and non-repeatable reads. Default in MySQL InnoDB.<br>- <strong>SERIALIZABLE</strong>: Prevents all anomalies. Slowest.", "code": "-- PostgreSQL: upgrade isolation for financial calculations\nBEGIN;\nSET TRANSACTION ISOLATION LEVEL SERIALIZABLE;\n\n-- Both reads will be consistent throughout this transaction\nSELECT SUM(balance) FROM accounts WHERE type = 'savings';\nSELECT SUM(balance) FROM accounts WHERE type = 'checking';\n\n-- If a concurrent conflict is detected:\n-- ERROR: could not serialize access due to concurrent update\n-- Catch this error and RETRY the transaction\nCOMMIT;\n\n-- Check current isolation level:\nSHOW transaction_isolation;               -- PostgreSQL\nSHOW VARIABLES LIKE 'transaction_isolation'; -- MySQL", "explain": "\"Most production applications run fine with READ COMMITTED — the default in PostgreSQL. For financial calculations that must be consistent — computing balances, detecting double-spending — I upgrade to SERIALIZABLE. The cost is serialization errors when transactions conflict, which you handle by catching the error and retrying the transaction.\"", "tip": "PostgreSQL implements REPEATABLE READ and SERIALIZABLE using MVCC (Multi-Version Concurrency Control) rather than locking, which means readers never block writers and writers never block readers. This makes high isolation levels much less of a performance penalty in PostgreSQL than in databases that implement them with traditional locking." },
{ "id": 23, "cat": "MongoDB", "tech": ["MongoDB"], "diff": "Medium", "q": "What is the MongoDB aggregation pipeline and when should you use it?", "a": "The <strong>aggregation pipeline</strong> is MongoDB's framework for processing and transforming documents through a sequence of stages. Each stage receives the output of the previous stage as its input — like an assembly line. It is the MongoDB equivalent of SQL's GROUP BY, JOIN, and aggregate functions.<br><br>Common stages: <code>$match</code> (filter — always put first for performance), <code>$group</code> (aggregate with sum, avg, count), <code>$project</code> (reshape output), <code>$lookup</code> (left join from another collection), <code>$unwind</code> (flatten arrays), <code>$sort</code>, <code>$limit</code>, <code>$skip</code>.", "code": "// Analytics: Top 5 customers by revenue this month\ndb.orders.aggregate([\n  // Stage 1: ALWAYS filter first to reduce document set!\n  { $match: {\n    status:    'completed',\n    createdAt: { $gte: new Date('2026-01-01') }\n  }},\n\n  // Stage 2: group by customer, compute metrics\n  { $group: {\n    _id:        '$customerId',\n    totalRev:   { $sum: '$amount' },\n    orderCount: { $sum: 1 }\n  }},\n\n  // Stage 3: join with customers collection\n  { $lookup: {\n    from: 'customers', localField: '_id',\n    foreignField: '_id', as: 'customer'\n  }},\n  { $unwind: '$customer' },\n\n  // Stage 4: reshape output\n  { $project: { name: '$customer.name', totalRev: 1, orderCount: 1 }},\n\n  { $sort:  { totalRev: -1 } },\n  { $limit: 5 }\n]);", "explain": "\"The aggregation pipeline is the most powerful MongoDB feature. I use it for all analytics queries — revenue reports, user activity summaries, product popularity. The critical performance rule: always put $match first to reduce the document set before expensive stages like $lookup or $group. A $lookup without a preceding $match can pull millions of documents into memory.\"", "tip": "For complex aggregations that serve dashboards, consider using MongoDB's $out or $merge stage to write results to a separate collection on a schedule. Dashboard queries then read from this pre-computed collection in milliseconds instead of running the aggregation pipeline on every single page load." },
{ "id": 24, "cat": "REST API", "tech": ["API", "REST"], "diff": "Medium", "q": "What is rate limiting and how do you implement it correctly across multiple server instances?", "a": "<strong>Rate limiting</strong> restricts how many requests a client can make to an API within a given time window. It protects against DDoS attacks, brute-force login attempts, API abuse, and prevents one client from monopolizing server resources.<br><br>Common algorithms:<br><strong>Fixed window</strong>: Allow N requests per time window. Simple but has a burst problem at window boundaries.<br><strong>Sliding window</strong>: More accurate — counts requests in the past N seconds from any point in time. No boundary burst problem.<br><strong>Token bucket</strong>: Clients accumulate tokens at a fixed rate up to a burst cap. Each request costs one token. Allows controlled bursting while enforcing a long-term rate.", "code": "// Distributed rate limiting with Redis (works across multiple servers)\nconst rateLimit  = require('express-rate-limit');\nconst RedisStore = require('rate-limit-redis').default;\n\n// General API: 100 requests per 15 minutes\nconst apiLimiter = rateLimit({\n  windowMs:        15 * 60 * 1000,\n  max:             100,\n  message:         { error: 'Too many requests, please try again later' },\n  standardHeaders: true,\n  legacyHeaders:   false,\n  // CRITICAL: Redis store for multi-server deployments!\n  // Without this, each server has its own independent counter\n  store: new RedisStore({\n    sendCommand: (...args) => redisClient.sendCommand(args)\n  }),\n});\n\n// Auth endpoints: much stricter (brute-force protection)\nconst loginLimiter = rateLimit({\n  windowMs: 15 * 60 * 1000,\n  max:      5,   // only 5 login attempts per 15 minutes!\n  message:  { error: 'Too many login attempts, please try again later' },\n});\n\napp.use('/api', apiLimiter);\napp.post('/auth/login', loginLimiter, loginHandler);", "explain": "\"Rate limiting is security plus reliability. For auth endpoints, I apply a very tight limit of 5 attempts per 15 minutes to prevent brute-force password attacks. The critical insight for multi-server deployments: if each Node.js instance tracks its own counter in memory, a user can make 100 requests per server and effectively bypass the limit entirely. Using Redis as the shared counter store ensures the limit is enforced globally across all instances.\"", "tip": "Always include rate limit headers in your responses — RateLimit-Limit, RateLimit-Remaining, and RateLimit-Reset. API consumers use these to build proper retry logic with exponential backoff. Also consider different limits for authenticated versus anonymous users — authenticated users typically get higher limits." },
{ "id": 25, "cat": "NestJS", "tech": ["NestJS", "Node.js"], "diff": "Medium", "q": "What are NestJS Guards, Interceptors, and Pipes and what is the difference between them?", "a": "NestJS provides a structured request lifecycle with several enhancement mechanisms, each with a specific responsibility:<br><br><strong>Guards</strong>: Determine whether a request should be allowed to proceed. Return true (allow) or false (deny). Run after middleware, before interceptors. Use for: authentication, authorization, role-based access control.<br><br><strong>Interceptors</strong>: Wrap the request and response cycle — they run before AND after the route handler. Use for: logging request duration, caching responses, transforming response shape, adding audit trails.<br><br><strong>Pipes</strong>: Transform or validate incoming data before it reaches the handler. Run after guards, before the handler. Use for: validating request bodies with class-validator, transforming string params to numbers, sanitizing input.<br><br>Request flow: Middleware → Guard → Interceptor (pre) → Pipe → Handler → Interceptor (post)", "code": "// Guard -- authentication check\n@Injectable()\nexport class JwtAuthGuard implements CanActivate {\n  canActivate(context: ExecutionContext): boolean {\n    const req   = context.switchToHttp().getRequest();\n    const token = req.headers.authorization?.replace('Bearer ', '');\n    if (!token) return false;\n    try { req.user = this.jwtService.verify(token); return true; }\n    catch { return false; }\n  }\n}\n\n// Interceptor -- wrap response in standard envelope\n@Injectable()\nexport class TransformInterceptor implements NestInterceptor {\n  intercept(ctx: ExecutionContext, next: CallHandler) {\n    const start = Date.now();\n    return next.handle().pipe(\n      map(data  => ({ success: true, data, timestamp: new Date() })),\n      tap(() => console.log(`Request: ${Date.now() - start}ms`))\n    );\n  }\n}\n\n// Pipe -- DTO validation\nclass CreateUserDto {\n  @IsString() @IsNotEmpty() name: string;\n  @IsEmail()               email: string;\n}\n\n@Post()\n@UseGuards(JwtAuthGuard)\ncreate(@Body(new ValidationPipe()) dto: CreateUserDto) {\n  return this.usersService.create(dto);\n}", "explain": "\"I explain the order as: middleware does low-level HTTP work, guards are the bouncers (are you allowed in?), interceptors are the experience wrappers (how do we present this?), and pipes are the input sanitizers (is your data valid?). In production I have a global JwtAuthGuard for all protected routes, a global ValidationPipe for all request bodies, and a global LoggingInterceptor that records every request duration for monitoring.\"", "tip": "Apply global guards, interceptors, and pipes using app.useGlobalGuards(), app.useGlobalInterceptors(), and app.useGlobalPipes() in main.ts. For public routes like /auth/login that need to bypass the global JwtAuthGuard, create a @Public() custom decorator and check for it inside the guard — if the route is marked public, return true immediately." },
{ "id": 26, "cat": "PostgreSQL", "tech": ["PostgreSQL"], "diff": "Medium", "q": "What is a database connection pool and why is it critical for production performance?", "a": "A <strong>connection pool</strong> is a cache of pre-established, reusable database connections. Establishing a new database connection requires TCP handshaking, SSL negotiation, authentication, and session setup — this takes 20-100ms per connection. In a high-traffic API handling hundreds of requests per second, creating a new connection for every query would be catastrophically slow.<br><br>A connection pool pre-creates N connections on application startup. Incoming queries borrow a connection, execute, and immediately return it to the pool. If all connections are in use, new queries wait briefly in a queue.", "code": "// Node.js + PostgreSQL using pg Pool\nconst { Pool } = require('pg');\n\nconst pool = new Pool({\n  host:                    process.env.DB_HOST,\n  database:                process.env.DB_NAME,\n  max:                     20,    // max simultaneous connections\n  min:                     2,     // keep minimum idle connections\n  idleTimeoutMillis:       30000, // close idle connections after 30s\n  connectionTimeoutMillis: 2000,  // fail fast if pool is exhausted\n});\n\n// pool.query handles checkout/return automatically\nasync function getUser(id) {\n  const { rows } = await pool.query(\n    'SELECT * FROM users WHERE id = $1', [id]\n  );\n  return rows[0]; // connection returned automatically\n}\n\n// For transactions: manually manage the connection\nasync function transfer(fromId, toId, amount) {\n  const client = await pool.connect();\n  try {\n    await client.query('BEGIN');\n    await client.query('UPDATE accounts SET balance = balance - $1 WHERE id = $2', [amount, fromId]);\n    await client.query('UPDATE accounts SET balance = balance + $1 WHERE id = $2', [amount, toId]);\n    await client.query('COMMIT');\n  } catch (e) {\n    await client.query('ROLLBACK');\n    throw e;\n  } finally {\n    client.release(); // ALWAYS release in finally!\n  }\n}", "explain": "\"Connection pool sizing requires balancing two constraints: PostgreSQL has a max_connections limit (usually 100-200), and each connection uses about 10MB of server RAM. If you have 10 app servers each with a pool of 20, that is 200 connections total — hitting the PostgreSQL limit. I use PgBouncer as a connection pooler between apps and PostgreSQL, multiplexing thousands of app pool connections onto a much smaller number of actual PostgreSQL connections.\"", "tip": "Never forget client.release() in a finally block. A connection that is checked out but never returned is a leaked connection. Over time, all pool connections leak and the application hangs waiting for a connection that never becomes available. Use pool.query() when you do not need transactions — it handles checkout and release automatically." },
{ "id": 27, "cat": "Integration", "tech": ["API", "Integration"], "diff": "Medium", "q": "What is a message queue and when would you use one in a backend architecture?", "a": "A <strong>message queue</strong> is a communication buffer that decouples services by allowing a producer to send messages that a consumer processes asynchronously. Instead of Service A calling Service B directly (tight coupling), A drops a message into the queue and B processes it whenever it is ready.<br><br>Key benefits:<br><strong>Decoupling</strong>: B can be down for maintenance and A keeps working — messages accumulate and B processes them when it recovers.<br><strong>Load leveling</strong>: Traffic spikes result in messages queuing rather than overwhelming the consumer.<br><strong>Retry logic</strong>: Failed messages are automatically retried with configurable backoff strategies.<br><strong>Scalability</strong>: Add more consumer instances to process faster without changing producers.<br><br>When to use: sending emails or notifications, image and video processing, generating PDF reports, payment processing, order fulfillment — any task that does not need an immediate synchronous response.", "code": "// BullMQ (Redis-based job queue for Node.js)\nconst { Queue, Worker } = require('bullmq');\nconst redis = { connection: { host: 'localhost', port: 6379 } };\n\n// Producer: API endpoint adds job and responds immediately\nconst emailQueue = new Queue('emails', redis);\n\napp.post('/orders', async (req, res) => {\n  const order = await db.createOrder(req.body);\n\n  // Queue the email -- don't wait for it to send!\n  await emailQueue.add('order-confirmation', {\n    to: order.customerEmail, orderId: order.id, total: order.total\n  }, {\n    attempts: 3,\n    backoff:  { type: 'exponential', delay: 2000 } // 2s, 4s, 8s\n  });\n\n  res.json({ orderId: order.id }); // instant response!\n});\n\n// Consumer: separate process handles email sending\nconst worker = new Worker('emails', async (job) => {\n  await emailClient.send(job.data);\n  console.log(`Email sent for order ${job.data.orderId}`);\n}, redis);", "explain": "\"Message queues answer the question: what do we do when a user action triggers work that takes more than a second? Without a queue, the user waits. With a queue, the order endpoint creates the database record and responds in milliseconds, while the email, inventory update, and fulfillment notification all happen in the background independently. If the email server is down, BullMQ retries automatically with exponential backoff.\"", "tip": "Use dead-letter queues for messages that fail after all retries. Instead of silently losing failed jobs, they move to the dead-letter queue where you can inspect them, fix the bug, and replay them. In BullMQ, failed jobs stay in the failed set and are accessible via the Bull Board dashboard." },
{ "id": 28, "cat": "TTL", "tech": ["Redis", "Caching"], "diff": "Medium", "q": "What is Redis caching and what are the main caching patterns?", "a": "<strong>Redis</strong> is an in-memory data structure store that is extremely fast (100,000+ operations per second) because everything lives in RAM. It is used as a cache, message broker, session store, rate limiter, and distributed lock.<br><br>Common caching patterns:<br><strong>Cache-aside (Lazy Loading)</strong>: Check cache first; on a miss, query the database and store the result in cache. Most common and versatile pattern.<br><strong>Write-through</strong>: Write to cache and database simultaneously on every update. Cache is always current but adds write latency.<br><strong>Write-behind</strong>: Write to cache immediately and persist to the database asynchronously. Highest performance but risk of data loss.<br><strong>Cache warming</strong>: Pre-populate the cache on application startup with frequently accessed data.", "code": "// Cache-aside pattern (most common)\nasync function getUserById(id) {\n  const cacheKey = `user:${id}`;\n\n  // 1. Check cache first\n  const cached = await redis.get(cacheKey);\n  if (cached) return JSON.parse(cached); // cache HIT\n\n  // 2. Cache MISS: query the database\n  const user = await db.query('SELECT * FROM users WHERE id = $1', [id]);\n  if (!user) return null;\n\n  // 3. Store in cache with 10-minute TTL\n  await redis.setEx(cacheKey, 600, JSON.stringify(user));\n  return user;\n}\n\n// Cache invalidation on update (critical!)\nasync function updateUser(id, data) {\n  await db.query('UPDATE users SET name=$1 WHERE id=$2', [data.name, id]);\n  await redis.del(`user:${id}`); // remove stale cache entry!\n}\n\n// Batch set multiple keys efficiently\nasync function cacheMultipleUsers(users) {\n  const pipeline = redis.multi();\n  users.forEach(u =>\n    pipeline.setEx(`user:${u.id}`, 600, JSON.stringify(u))\n  );\n  await pipeline.exec(); // all commands sent in one round trip\n}", "explain": "\"Cache-aside is my default pattern. The flow: check Redis first (fast), fall back to the database (slow) on a miss, then populate the cache for next time. The two critical decisions: what TTL to use — shorter for frequently changing data, longer for stable data — and when to invalidate. I always delete the cache key when the underlying data changes, never rely solely on the TTL to serve consistent data.\"", "tip": "Monitor your cache hit rate. Below 80% means too much data is missing the cache and you are making most database calls anyway — the cache provides little benefit. Above 99% for a long time might mean TTLs are too long and users are seeing stale data. Use Redis INFO stats command to track hits and misses continuously." },
{ "id": 29, "cat": "Python", "tech": ["Python"], "diff": "Medium", "q": "What is Python asyncio and how does it enable high-concurrency backends?", "a": "<strong>asyncio</strong> is Python's built-in library for writing concurrent code using coroutines. Like Node.js, it uses an event loop and non-blocking I/O — a single thread can handle thousands of concurrent I/O-bound operations simultaneously by pausing operations that are waiting and resuming them when results arrive.<br><br>Key concepts:<br><strong>async def</strong>: Defines a coroutine function — a function that can be suspended and resumed.<br><strong>await</strong>: Pauses the current coroutine until the awaited operation completes, yielding control to the event loop to handle other work.<br><strong>asyncio.gather()</strong>: Runs multiple coroutines concurrently — they all start and run simultaneously.<br><strong>aiohttp, asyncpg, motor</strong>: Async-native libraries for HTTP, PostgreSQL, and MongoDB.", "code": "import asyncio\nimport aiohttp\n\nasync def fetch_user(session, user_id: int) -> dict:\n    async with session.get(f'https://api.example.com/users/{user_id}') as resp:\n        return await resp.json()\n\nasync def get_users_concurrently(ids: list[int]) -> list[dict]:\n    async with aiohttp.ClientSession() as session:\n        # All requests start simultaneously!\n        tasks = [fetch_user(session, uid) for uid in ids]\n        return await asyncio.gather(*tasks)\n\nasync def main():\n    # Sequential: 100 requests x 200ms = 20 seconds\n    # Concurrent: max(200ms) = ~200ms (100x faster!)\n    users = await get_users_concurrently(range(1, 101))\n    print(f'Fetched {len(users)} users')\n\nasyncio.run(main())", "explain": "\"asyncio in Python is conceptually identical to Node.js — one thread, non-blocking I/O, concurrency through coroutines. FastAPI is built entirely on asyncio, which is why it can match Node.js performance for I/O-heavy API workloads despite being Python. The key insight: fetching 100 external APIs sequentially takes 100 times 200ms equals 20 seconds. With asyncio.gather(), all 100 requests start simultaneously and total time is approximately 200ms.\"", "tip": "asyncio handles I/O concurrency but Python's GIL still prevents true CPU parallelism in a single process. For CPU-bound tasks like image processing or data transformation, use asyncio.run_in_executor() with a ProcessPoolExecutor to run work in separate processes that bypass the GIL. Think: asyncio for I/O concurrency, multiprocessing for CPU parallelism." },
{ "id": 30, "cat": "Java", "tech": ["Java", "Spring"], "diff": "Medium", "q": "What is dependency injection in Spring and why does it make code testable?", "a": "<strong>Dependency Injection (DI)</strong> is a design pattern where an object receives its dependencies from an external source (the Spring IoC container) rather than creating them internally. Instead of writing <code>new UserRepository()</code> inside UserService, Spring creates the UserRepository and injects it into UserService automatically.<br><br>Why this matters for testability: when dependencies are injected, they can be replaced with mock implementations in unit tests without changing any production code. You can test UserService in complete isolation by injecting a mock repository that returns controlled test data, without needing a real database connection.", "code": "// Without DI -- tightly coupled, impossible to unit test properly\npublic class UserService {\n    private UserRepository repo  = new UserRepository(); // hard-coded!\n    private EmailService   email = new EmailService();   // can't mock!\n}\n\n// With Spring DI -- loosely coupled, fully testable\n@Service\npublic class UserService {\n    private final UserRepository userRepo;\n    private final EmailService   emailService;\n\n    // Constructor injection -- preferred over @Autowired field injection!\n    public UserService(UserRepository userRepo, EmailService emailService) {\n        this.userRepo     = userRepo;\n        this.emailService = emailService;\n    }\n}\n\n// Unit test: inject mock dependencies\n@ExtendWith(MockitoExtension.class)\nclass UserServiceTest {\n    @Mock UserRepository mockRepo;\n    @Mock EmailService   mockEmail;\n    @InjectMocks UserService userService;\n\n    @Test void shouldCreateUserAndSendEmail() {\n        when(mockRepo.save(any())).thenReturn(new User(\"Alice\", \"a@x.com\"));\n        userService.createUser(new CreateUserDto(\"Alice\", \"a@x.com\"));\n        verify(mockEmail, times(1)).sendWelcome(\"a@x.com\");\n    }\n}", "explain": "\"Dependency injection is the cornerstone of testable, maintainable code. I explain it as: instead of a chef buying their own groceries (creating dependencies), a supplier delivers exactly what is needed (injected by the container). Constructor injection is preferred over @Autowired field injection because it makes dependencies visible, enables immutable final fields, and allows creating the class without a Spring context in plain unit tests.\"", "tip": "Prefer constructor injection over @Autowired field injection everywhere. It makes dependencies explicit, allows marking them final (immutable after construction), and makes the class usable in plain unit tests without a Spring context. If a class needs more than 4-5 constructor parameters, it is a signal the class has too many responsibilities and should be refactored." },
{ "id": 31, "cat": "Server Management", "tech": ["DevOps"], "diff": "Medium", "q": "What is CI/CD and how does it improve backend development and deployment?", "a": "<strong>CI/CD</strong> (Continuous Integration / Continuous Delivery) is the practice of automating the build, test, and deployment pipeline every time code is pushed to the repository.<br><br><strong>Continuous Integration (CI)</strong>: Every push automatically triggers linting, unit tests, integration tests, and a production build. Catches bugs before they reach the main branch.<br><br><strong>Continuous Delivery (CD)</strong>: Automated deployment to staging after CI passes. Production deployment requires manual approval.<br><br><strong>Continuous Deployment</strong>: Automated deployment all the way to production — no manual intervention if all tests pass.", "code": "# .github/workflows/api.yml (GitHub Actions)\nname: Backend CI/CD\non:\n  push:\n    branches: [main, develop]\n  pull_request:\n    branches: [main]\n\njobs:\n  test:\n    runs-on: ubuntu-latest\n    services:\n      postgres:\n        image: postgres:16\n        env: { POSTGRES_PASSWORD: testpass }\n        ports: ['5432:5432']\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with: { node-version: '20' }\n      - run: npm ci\n      - run: npm run lint\n      - run: npm test\n        env: { DATABASE_URL: postgresql://postgres:testpass@localhost:5432/testdb }\n\n  deploy:\n    needs: test\n    if: github.ref == 'refs/heads/main'\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - name: Deploy to production\n        run: |\n          ssh deploy@myserver.com 'cd /app &&\n          git pull && npm ci --omit=dev &&\n          npm run build && pm2 restart api'", "explain": "\"CI/CD transformed how I deploy. Before: manual deployments, fear of deploying on Fridays, big-bang releases that were hard to debug. With CI/CD: every PR gets tests run automatically, merging to main triggers deployment within minutes, and if something breaks you can roll back in 30 seconds.\"", "tip": "Keep your test suite fast — if CI takes 20 minutes, developers stop waiting for it and push anyway, defeating the purpose. Target under 5 minutes for the full test run. Never hard-code secrets in CI config files — use the platform's secrets management system." },
{ "id": 32, "cat": "Databases", "tech": ["PostgreSQL", "MySQL"], "diff": "Medium", "q": "What is the N+1 query problem and how do you solve it?", "a": "The <strong>N+1 query problem</strong> occurs when code executes one query to fetch N records, then executes one additional query per record to fetch related data — resulting in N+1 total database queries instead of 1 or 2 efficient queries.<br><br>It is the most common database performance problem in web applications. The difference between 1 query and 100 queries is often the difference between a 10ms response and a 2-second timeout under load.", "code": "// N+1 Problem (Sequelize example)\nconst orders = await Order.findAll();      // Query 1: get 100 orders\nfor (const order of orders) {\n  const user = await order.getUser();      // Queries 2-101: one per order!\n  console.log(`${user.name}: ${order.total}`);\n}\n// Total: 101 database queries. Terrible.\n\n// Solution 1: Eager loading with JOIN (1 query)\nconst orders = await Order.findAll({\n  include: [{ model: User, attributes: ['name', 'email'] }]\n});\n// Generates a LEFT JOIN -- one query, same result\n\n// Solution 2: Separate WHERE IN query (2 queries)\nconst orders  = await Order.findAll();\nconst userIds = [...new Set(orders.map(o => o.userId))];\nconst users   = await User.findAll({ where: { id: userIds } });\nconst userMap = Object.fromEntries(users.map(u => [u.id, u]));\norders.forEach(o => { o.user = userMap[o.userId]; });\n\n// Solution 3: DataLoader for GraphQL (batches automatically)\nconst userLoader = new DataLoader(async (ids) => {\n  const users = await User.findAll({ where: { id: ids } });\n  return ids.map(id => users.find(u => u.id === id));\n});", "explain": "\"The N+1 problem is the first thing I look for in code review when someone reports a slow page. The fix is usually a one-line change in an ORM — add include or with to eager-load the association. In development I enable query logging: in Sequelize set logging: console.log. If you see the same SQL query repeated 50 times with different WHERE id = X values, you have found an N+1 problem.\"", "tip": "In production, use pg_stat_statements in PostgreSQL or the slow query log in MySQL to find your most-called and slowest queries automatically. A query that runs 10,000 times per minute at 10ms each contributes 1.7 minutes of database load per minute — catch these with APM tools, not just by waiting for user complaints." },
{ "id": 33, "cat": "PHP", "tech": ["PHP"], "diff": "Medium", "q": "What are PHP traits and why are they useful in modern PHP development?", "a": "<strong>Traits</strong> are a mechanism for horizontal code reuse in PHP's single-inheritance model. PHP classes can only extend one parent class, but they can use multiple traits. A trait defines methods that are effectively copy-pasted into the class that uses it at compile time — without requiring an inheritance relationship.<br><br>Traits solve the problem of sharing functionality between classes that do not share a logical 'is-a' relationship. They are one of PHP's most powerful features for keeping code DRY without creating awkward inheritance hierarchies.", "code": "<?php\ntrait Timestampable {\n    protected ?DateTime $createdAt = null;\n    protected ?DateTime $updatedAt = null;\n\n    public function setCreatedAt(): void {\n        $this->createdAt = new DateTime();\n    }\n    public function setUpdatedAt(): void {\n        $this->updatedAt = new DateTime();\n    }\n}\n\ntrait SoftDeletable {\n    protected ?DateTime $deletedAt = null;\n\n    public function softDelete(): void {\n        $this->deletedAt = new DateTime();\n    }\n    public function isDeleted(): bool {\n        return $this->deletedAt !== null;\n    }\n}\n\n// Two completely unrelated models share the same behaviors\nclass User {\n    use Timestampable, SoftDeletable;\n    public function __construct(public string $name) {\n        $this->setCreatedAt();\n    }\n}\n\nclass Post {\n    use Timestampable, SoftDeletable;\n    public function __construct(public string $title) {\n        $this->setCreatedAt();\n    }\n}", "explain": "\"Traits are PHP's answer to the mixin pattern. The problem they solve: User and Post are completely different entities with no logical inheritance relationship, but both need timestamp and soft-delete functionality. Without traits, you would duplicate code or create an awkward base class. Laravel uses traits extensively — SoftDeletes, HasTimestamps, Notifiable, and HasApiTokens are all traits you mix into your Eloquent models.\"", "tip": "Traits can conflict if two traits define the same method name. PHP requires you to explicitly resolve the conflict: use TraitA, TraitB { TraitA::log insteadof TraitB; TraitB::log as logFromB; }. Always document which traits a class uses since trait conflicts can create confusing bugs." },
{ "id": 34, "cat": "Server Management", "tech": ["Linux", "Server"], "diff": "Medium", "q": "What is load balancing and what are the common algorithms used?", "a": "<strong>Load balancing</strong> distributes incoming traffic across multiple backend servers to prevent any single server from becoming a bottleneck. It enables horizontal scaling, high availability, and better resource utilization.<br><br>Common algorithms:<br><strong>Round Robin</strong>: Requests go to each server in rotation. Simple, works well when servers have similar capacity and request processing time is roughly equal.<br><strong>Weighted Round Robin</strong>: Servers with higher weight receive proportionally more requests. Useful when servers have different capacities.<br><strong>Least Connections</strong>: New request goes to the server with the fewest currently active connections. Better when request processing times vary significantly.<br><strong>IP Hash</strong>: The client's IP address determines which server handles it — the same client always routes to the same server. Use for session affinity.", "code": "# Nginx load balancing configuration\nupstream api_backends {\n    least_conn;  # least-connections algorithm\n\n    server api-1.internal:3000 weight=3;  # gets 75% of traffic\n    server api-2.internal:3000 weight=1;  # gets 25% of traffic\n    server api-3.internal:3000;\n\n    keepalive 32;  # maintain persistent connections to backends\n}\n\nserver {\n    listen 80;\n    location /api {\n        proxy_pass       http://api_backends;\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n\n        # Remove unhealthy servers from rotation automatically\n        proxy_next_upstream error timeout http_500 http_502 http_503;\n    }\n}", "explain": "\"Load balancing is the foundation of horizontal scalability. I use the bank teller analogy: instead of one teller serving everyone, multiple tellers share the queue. Least Connections is smarter than Round Robin — if one server is handling a slow request and others are free, new customers go to the free servers automatically. For stateless REST APIs where all state lives in the database, round robin or least connections work perfectly.\"", "tip": "Implement health checks in your load balancer so it automatically stops sending traffic to unhealthy servers. In Nginx, use the proxy_next_upstream directive. Always implement a /healthz endpoint in your application that returns 200 OK only when the service is genuinely ready to handle traffic." },
{ "id": 35, "cat": "Node.js", "tech": ["Node.js"], "diff": "Medium", "q": "How do you implement proper error handling and logging in a production Node.js API?", "a": "Production error handling requires a systematic approach: catching all errors both sync and async, not leaking sensitive information to clients, logging errors with full context for debugging, and monitoring error rates.<br><br>Key components:<br><strong>Global error handler</strong>: Express 4-parameter error middleware (err, req, res, next) catches all errors passed via next(err).<br><strong>Unhandled rejection handler</strong>: process.on('unhandledRejection') catches Promise rejections that were not caught anywhere in the call chain.<br><strong>Structured logging</strong>: Use Pino or Winston for JSON-formatted logs with severity levels, timestamps, request IDs, and user context.<br><strong>Error monitoring</strong>: Sentry, Datadog, or New Relic capture full stack traces in production automatically.", "code": "const pino   = require('pino');\nconst logger = pino({ level: 'info' });\n\n// Custom error class\nclass AppError extends Error {\n  constructor(message, statusCode = 500, code = 'INTERNAL_ERROR') {\n    super(message);\n    this.statusCode    = statusCode;\n    this.code          = code;\n    this.isOperational = true; // expected error, safe to expose\n  }\n}\n\n// Async wrapper -- avoids try/catch in every handler\nconst asyncHandler = fn => (req, res, next) =>\n  Promise.resolve(fn(req, res, next)).catch(next);\n\n// Global error handler -- MUST be last app.use() call!\napp.use((err, req, res, next) => {\n  logger.error({ err, requestId: req.id, userId: req.user?.id });\n\n  // Never leak internals in production!\n  if (process.env.NODE_ENV === 'production' && !err.isOperational) {\n    return res.status(500).json({ error: 'Internal Server Error' });\n  }\n  res.status(err.statusCode || 500).json({ error: err.message, code: err.code });\n});\n\n// Crash safety net\nprocess.on('unhandledRejection', (reason) => {\n  logger.error('Unhandled Promise Rejection:', reason);\n  process.exit(1); // let PM2 restart gracefully\n});", "explain": "\"Error handling has two audiences: the client needs a clean, safe message, and the developer needs full context to debug. I use a custom AppError class to distinguish between operational errors (expected — 404, 403) and programming bugs (unexpected). Operational errors show their message to the client. Programming errors show a generic Internal Server Error in production, preventing stack traces and system details from leaking.\"", "tip": "Assign a unique UUID request ID to every incoming request and include it in both the response header (X-Request-ID) and every log line for that request. When a user reports an error, they share the request ID and you find all related log entries across every service in seconds." },
{ "id": 36, "cat": "MongoDB", "tech": ["MongoDB"], "diff": "Medium", "q": "What is the difference between embedding and referencing in MongoDB schema design?", "a": "<strong>Embedding</strong> (denormalization): Store related data inside the same document. One query retrieves everything. Best for: data that is always read together, bounded relationships (a blog post's comments), and data that does not change independently of the parent.<br><br><strong>Referencing</strong> (normalization): Store an ObjectId that references another document. Requires a second query or $lookup. Best for: large or unbounded data, data shared across many documents, and data that changes or is accessed independently.<br><br>The fundamental decision rule: <strong>if you always read them together, embed; if you use them independently, reference.</strong>", "code": "// Embedding -- blog post with bounded comments\n// Good: post and comments always fetched together\n{\n  _id: 'post1',\n  title: 'MongoDB Schema Design',\n  comments: [\n    { user: 'bob',   text: 'Great post!', date: '2026-01-01' },\n    { user: 'carol', text: 'Very helpful', date: '2026-01-02' }\n  ]\n}\n// db.posts.findOne({ _id: 'post1' }) fetches everything\n\n// Referencing -- order referencing a product\n// Good: product exists independently, has its own lifecycle\n{\n  _id: 'order1',\n  userId:    ObjectId('user1'),    // reference\n  productId: ObjectId('prod1'),    // reference\n  quantity: 2,\n  priceAtPurchase: 299             // snapshot price at time of order!\n}\n\n// When to always reference:\n// 1. Array could grow unboundedly (user's all-time tweets)\n// 2. Child accessed frequently without the parent\n// 3. Same document referenced from many places", "explain": "\"I use the access pattern question to decide: do I ever need the child data without the parent? If yes, reference it. Will the embedded array grow unboundedly over time? Reference it — MongoDB has a hard 16MB document size limit. Is the child document referenced from multiple parents? Reference it so updates propagate correctly.\"", "tip": "MongoDB has a hard 16MB size limit per document. An embedded array that grows forever — like all of a user's activity events — will eventually hit this limit and make it impossible to add new items. This is always the clearest signal to switch from embedding to referencing." },
{ "id": 37, "cat": "Java", "tech": ["Java"], "diff": "Medium", "q": "What are the most important Java design patterns used in enterprise backend development?", "a": "Design patterns are reusable solutions to commonly recurring design problems. The most important ones for enterprise Java backend:<br><br><strong>Singleton</strong>: Exactly one instance of a class — database connection pool, application config. Spring beans are singletons by default.<br><strong>Factory</strong>: Create objects without specifying the exact class. Used in Spring's BeanFactory and JDBC DriverManager.<br><strong>Builder</strong>: Construct complex objects step by step. Lombok's @Builder annotation generates it automatically.<br><strong>Repository</strong>: Abstract the data access layer from business logic. Foundation of Spring Data repositories.<br><strong>Strategy</strong>: Define a family of interchangeable algorithms. Payment processors, notification channels, storage backends.<br><strong>Observer</strong>: Publish-subscribe event pattern. Spring's ApplicationEvent and @EventListener.", "code": "// Strategy Pattern -- pluggable payment processing\npublic interface PaymentStrategy {\n    PaymentResult process(PaymentRequest request);\n}\n\n@Service(\"stripe\")\npublic class StripeStrategy implements PaymentStrategy {\n    public PaymentResult process(PaymentRequest req) {\n        return stripeClient.charge(req.getAmount(), req.getToken());\n    }\n}\n\n@Service(\"razorpay\")\npublic class RazorpayStrategy implements PaymentStrategy {\n    public PaymentResult process(PaymentRequest req) {\n        return razorpayClient.capturePayment(req);\n    }\n}\n\n// Service selects strategy by name -- no switch statements!\n@Service\npublic class PaymentService {\n    private final Map&lt;String, PaymentStrategy&gt; strategies;\n    public PaymentService(Map&lt;String, PaymentStrategy&gt; strategies) {\n        this.strategies = strategies; // Spring injects all implementations!\n    }\n    public PaymentResult pay(String provider, PaymentRequest req) {\n        return strategies.get(provider).process(req);\n    }\n}\n// Adding a new provider = just add a new class. Zero other changes.", "explain": "\"The Strategy pattern is one I use constantly for anything pluggable — payment providers, notification channels (email, SMS, push), shipping carriers. Spring's dependency injection makes it effortless: define an interface, implement it for each strategy, and inject them as Map<String, Strategy>. Adding a new payment provider means just adding a new class annotated with @Service — no changes to PaymentService.\"", "tip": "Most design patterns in enterprise Java are implemented implicitly by Spring Boot: Singleton (Spring beans), Factory (BeanFactory), Template Method (JdbcTemplate, RestTemplate), Observer (ApplicationEvent). Understanding the underlying pattern helps you use these Spring abstractions more effectively." },
{ "id": 38, "cat": "C / C++", "tech": ["C", "C++"], "diff": "Medium", "q": "What is RAII in C++ and how does it prevent resource leaks?", "a": "<strong>RAII (Resource Acquisition Is Initialization)</strong> is a C++ programming idiom where resources — memory, file handles, network connections, mutexes — are tied to the lifetime of an object. Resources are acquired in the constructor and released in the destructor. When the object goes out of scope, whether by normal exit, early return, or exception, the destructor automatically releases the resource.<br><br>RAII eliminates the need for manual resource management and guarantees cleanup even in exceptional code paths. It is the reason modern C++ has far fewer memory leaks than C, without a garbage collector. Smart pointers (unique_ptr, shared_ptr), lock_guard, and fstream all implement RAII.", "code": "#include &lt;memory&gt;\n#include &lt;mutex&gt;\n#include &lt;fstream&gt;\n#include &lt;stdexcept&gt;\n\n// RAII with unique_ptr -- memory freed automatically\nvoid processData() {\n    auto buffer = std::make_unique&lt;char[]&gt;(1024 * 1024);\n    if (someError) throw std::runtime_error(\"Error\");\n    // Whether we return normally OR throw:\n    // buffer is freed automatically by unique_ptr destructor!\n}\n\n// RAII with lock_guard -- mutex released automatically\nstd::mutex mtx;\nvoid safeUpdate(int& counter) {\n    std::lock_guard&lt;std::mutex&gt; lock(mtx); // acquire lock\n    counter++;  // safe from concurrent access\n    // lock released automatically -- even if exception is thrown!\n}\n\n// RAII with fstream -- file closed automatically\nvoid writeConfig(const std::string& path, const std::string& data) {\n    std::ofstream file(path);\n    if (!file) throw std::runtime_error(\"Cannot open file\");\n    file &lt;&lt; data;\n    // file closed automatically in ofstream destructor\n}", "explain": "\"RAII is C++'s most important idiom and the reason smart pointers exist. Without RAII, every early return, every exception, every branch that holds a resource requires manual cleanup — and missing one causes a leak. With RAII, cleanup is guaranteed regardless of how code exits. Modern C++ with RAII and smart pointers has essentially the same safety as Java or Go garbage collection, with the added benefit of deterministic, zero-overhead cleanup.\"", "tip": "In modern C++, avoid raw new and delete entirely. Use make_unique for single ownership and make_shared for shared ownership. Raw pointers are fine for non-owning references — observing data without being responsible for its lifetime." },
{ "id": 39, "cat": "Databases", "tech": ["PostgreSQL", "MySQL"], "diff": "Hard", "q": "How do you approach database query optimization systematically?", "a": "Query optimization is the systematic process of reducing the work the database must do to return results. PostgreSQL's query planner generates execution plans and chooses the lowest-cost plan — understanding how to read these plans is the core skill.<br><br>Systematic approach:<br>1. <strong>EXPLAIN ANALYZE</strong>: The only reliable way to understand what the database actually does and how long each step takes. Never guess — always measure.<br>2. <strong>Identify the bottleneck</strong>: Look for Seq Scan on large tables, high actual row counts, sorts on large datasets without an index.<br>3. <strong>Add targeted indexes</strong>: On WHERE, JOIN, and ORDER BY columns. Composite indexes should put equality conditions first and range conditions last.<br>4. <strong>Rewrite the query</strong>: Avoid functions on indexed columns. Use CTEs to make complex queries readable.<br>5. <strong>Materialized views</strong>: For expensive aggregate queries that run frequently.<br>6. <strong>Keep statistics fresh</strong>: ANALYZE updates planner statistics — essential after large data imports.", "code": "-- Step 1: Get the actual execution plan with real timing\nEXPLAIN (ANALYZE, BUFFERS, FORMAT TEXT)\nSELECT u.name, COUNT(o.id) AS orders, SUM(o.total) AS revenue\nFROM users u\nJOIN orders o ON o.user_id = u.id\nWHERE o.status = 'completed'\n  AND o.created_at &gt;= '2026-01-01'\nGROUP BY u.id, u.name\nHAVING SUM(o.total) &gt; 1000\nORDER BY revenue DESC\nLIMIT 20;\n-- Look for: Seq Scan on large tables, actual vs estimated rows\n\n-- Step 2: Composite index (equality first, range last)\nCREATE INDEX idx_orders_status_date\n  ON orders(user_id, status, created_at)\n  WHERE status = 'completed'; -- partial index!\n\n-- Step 3: Never wrap indexed columns in functions\n-- BAD:  WHERE DATE(created_at) = '2026-01-15'   (full scan)\n-- GOOD: WHERE created_at &gt;= '2026-01-15' AND created_at &lt; '2026-01-16'\n\n-- Step 4: Materialized view for dashboard queries\nCREATE MATERIALIZED VIEW user_revenue_summary AS\nSELECT user_id, SUM(total) AS revenue, COUNT(*) AS order_count\nFROM orders WHERE status = 'completed' GROUP BY user_id WITH DATA;\nREFRESH MATERIALIZED VIEW CONCURRENTLY user_revenue_summary;", "explain": "\"My optimization process always starts with EXPLAIN ANALYZE — never just EXPLAIN, you need actual timings and row counts. I look for the widest operation in the plan tree — that is usually the bottleneck. A Seq Scan reading 20MB of data on a million-row table is often fixable with one index. For a dashboard query that runs 1000 times per hour, a materialized view refreshed every 5 minutes gives millisecond response instead of multi-second aggregation on every load.\"", "tip": "Use pg_stat_statements to find your slowest and most-called queries automatically: SELECT query, total_exec_time, calls, mean_exec_time FROM pg_stat_statements ORDER BY total_exec_time DESC LIMIT 10. This shows the 10 queries consuming the most total database time — these are the highest-leverage targets for optimization." },
{ "id": 40, "cat": "Node.js", "tech": ["Node.js"], "diff": "Hard", "q": "How do you implement a circuit breaker pattern to prevent cascading failures in microservices?", "a": "A <strong>circuit breaker</strong> prevents cascading failures in distributed systems. When Service A calls Service B and B starts failing or timing out, without a circuit breaker, A keeps trying — exhausting its connection pool and eventually failing itself. The circuit breaker monitors the failure rate and opens the circuit when failures exceed a threshold, immediately rejecting calls with a fallback instead of waiting for timeouts.<br><br>Three states: <strong>Closed</strong> (normal — requests flow through), <strong>Open</strong> (failures too high — requests rejected immediately), <strong>Half-Open</strong> (recovery probe — allows one test request; closes circuit if it succeeds, reopens if it fails).", "code": "class CircuitBreaker {\n  constructor(fn, options = {}) {\n    this.fn               = fn;\n    this.failureThreshold = options.failureThreshold || 5;\n    this.successThreshold = options.successThreshold || 2;\n    this.timeout          = options.timeout          || 60000;\n    this.state            = 'CLOSED';\n    this.failureCount     = 0;\n    this.successCount     = 0;\n    this.nextAttemptTime  = null;\n  }\n\n  async call(...args) {\n    if (this.state === 'OPEN') {\n      if (Date.now() &lt; this.nextAttemptTime)\n        throw new Error('Circuit OPEN -- service unavailable');\n      this.state = 'HALF_OPEN';\n    }\n    try {\n      const result = await Promise.race([\n        this.fn(...args),\n        new Promise((_, r) => setTimeout(() => r(new Error('Timeout')), 5000))\n      ]);\n      this.onSuccess(); return result;\n    } catch (err) {\n      this.onFailure(); throw err;\n    }\n  }\n\n  onSuccess() {\n    this.failureCount = 0;\n    if (this.state === 'HALF_OPEN' &&\n        ++this.successCount &gt;= this.successThreshold) {\n      this.state = 'CLOSED'; this.successCount = 0;\n    }\n  }\n  onFailure() {\n    if (++this.failureCount &gt;= this.failureThreshold) {\n      this.state = 'OPEN';\n      this.nextAttemptTime = Date.now() + this.timeout;\n    }\n  }\n}\n\nconst paymentBreaker = new CircuitBreaker(paymentService.charge);\ntry {\n  await paymentBreaker.call(paymentData);\n} catch (err) {\n  await retryQueue.add(paymentData); // fallback: queue for retry\n}", "explain": "\"Without a circuit breaker, if the payment service goes down, every checkout request waits for a 30-second timeout before failing — the server thread pool exhausts and the entire checkout page goes down. With a circuit breaker, after 5 failures, requests fail immediately with a user-friendly error and the checkout page stays functional. The Half-Open state is the recovery probe — it lets one test request through to check if the downstream service has recovered.\"", "tip": "In production, use opossum for Node.js or Resilience4j for Java rather than implementing your own circuit breaker. They handle edge cases like Half-Open state concurrency, accurate failure rate calculation, and emit events you can monitor. Expose circuit breaker state in your health endpoint so your monitoring system can alert when a circuit opens." },
{ "id": 41, "cat": "Security", "tech": ["API", "Security"], "diff": "Hard", "q": "What are the most critical backend API security vulnerabilities and how do you prevent them?", "a": "<strong>OWASP</strong> maintains the API Security Top 10. The most critical vulnerabilities for backend developers:<br><br><strong>BOLA/IDOR (Broken Object Level Authorization)</strong>: User A can access User B's data by changing an ID in the request URL. The most common API vulnerability and is missed constantly.<br><br><strong>SQL Injection</strong>: Unsanitized user input executed as SQL commands — 100% preventable with parameterized queries.<br><br><strong>Broken Authentication</strong>: Weak tokens, no rate limiting on auth endpoints.<br><br><strong>Excessive Data Exposure</strong>: API returns full database objects (passwords hashes, internal IDs) and trusts clients to filter what is shown.<br><br><strong>Security Misconfiguration</strong>: Default passwords, exposed admin panels, verbose stack traces in production.", "code": "// BOLA -- most common API vulnerability\n\n// VULNERABLE: any authenticated user accesses any order\napp.get('/api/orders/:orderId', authenticate, async (req, res) => {\n  const order = await Order.findById(req.params.orderId);\n  res.json(order); // USER A CAN READ USER B'S ORDERS!\n});\n\n// FIXED: always verify the authenticated user owns this resource\napp.get('/api/orders/:orderId', authenticate, async (req, res) => {\n  const order = await Order.findOne({\n    _id:    req.params.orderId,\n    userId: req.user.id    // MUST match the authenticated user!\n  });\n  if (!order) return res.status(404).json({ error: 'Not found' });\n  res.json(order);\n});\n\n// Excessive Data Exposure -- FIXED with explicit whitelist\nconst user = await User.findById(req.params.id)\n  .select('name email avatar bio createdAt -_id');\nres.json(user); // only safe, public fields", "explain": "\"BOLA is the most common API vulnerability I find in code reviews. A developer writes authentication, thinks the API is secure, but never verifies ownership. The fix is a rule I enforce in every code review: for every endpoint that retrieves a resource by ID, the WHERE clause must include the authenticated user ID. The query must be find where id = X AND userId = currentUser.id — never just find where id = X after checking authentication.\"", "tip": "Use OWASP ZAP for free automated API security testing in your CI pipeline. Also implement security response headers via helmet.js — it sets Content-Security-Policy, X-Frame-Options, and 8 other security headers in one line. Never expose stack traces in production responses." },
{ "id": 42, "cat": "Databases", "tech": ["PostgreSQL", "MySQL"], "diff": "Hard", "q": "How do you handle database schema migrations safely in production without downtime?", "a": "Database schema migrations in production are the most dangerous deployment operation. Safe migrations require the <strong>Expand-Contract pattern</strong> for zero-downtime execution:<br><br><strong>Expand phase</strong>: Add new columns or tables alongside existing ones, nullable so old code still works. Deploy new code that writes to BOTH old and new columns simultaneously.<br><br><strong>Migrate phase</strong>: Backfill existing data in small batches to avoid locking.<br><br><strong>Contract phase</strong>: Remove the old column after all application instances have been updated and no code reads from it anymore.<br><br>Each phase is a separate, independently deployed change. Never do all three in one deployment.", "code": "-- PHASE 1 (Expand): Add column as nullable -- no breaking change\nALTER TABLE users ADD COLUMN phone_e164 VARCHAR(20);\n\n-- PHASE 2 (Migrate): Backfill in small batches\nDO $$\nDECLARE batch INT := 1000; cur INT := 0; mx INT;\nBEGIN\n  SELECT MAX(id) INTO mx FROM users;\n  WHILE cur &lt; mx LOOP\n    UPDATE users SET phone_e164 = format_e164(phone)\n    WHERE id &gt; cur AND id &lt;= cur + batch\n      AND phone IS NOT NULL AND phone_e164 IS NULL;\n    cur := cur + batch;\n    PERFORM pg_sleep(0.01); -- brief pause per batch\n  END LOOP;\nEND $$;\n\n-- PHASE 3 (Contract): Non-blocking index creation\nCREATE INDEX CONCURRENTLY idx_phone_e164 ON users(phone_e164);\n\n-- PHASE 4: Add NOT NULL after all old code is removed\nALTER TABLE users ALTER COLUMN phone_e164 SET NOT NULL;\n\n-- PHASE 5: Drop old column after verifying nothing reads it\nALTER TABLE users DROP COLUMN phone;", "explain": "\"Schema migrations are where I have seen the most production incidents. Three rules I never break: never rename or drop a column in the same deploy that removes it from application code; always create indexes with CONCURRENTLY to avoid locking the table; always backfill data in small batches with brief pauses to avoid overwhelming I/O.\"", "tip": "Set LOCK TIMEOUT and STATEMENT TIMEOUT before running migrations: SET lock_timeout = '2s'; SET statement_timeout = '60s'. This ensures the migration fails fast rather than waiting indefinitely if it cannot acquire a lock, preventing it from blocking all subsequent database access for minutes." },
{ "id": 43, "cat": "Integration", "tech": ["API", "Architecture"], "diff": "Hard", "q": "What is event sourcing and how does it differ from traditional CRUD?", "a": "<strong>Event sourcing</strong> is an architectural pattern where instead of storing the current state of an entity, you store the complete sequence of events that led to that state. The current state is derived at query time by replaying all events.<br><br>Traditional CRUD: <code>UPDATE accounts SET balance = 500 WHERE id = 1</code> — overwrites state, no history.<br><br>Event sourcing: Append events — BalanceDebited(500), BalanceCredited(200) — current state is always derivable by summing all events.<br><br>Benefits: Complete, permanent audit trail. Temporal queries — what was the state at any point in time? Easy debugging by replaying events. Natural fit for event-driven integrations.", "code": "// Event sourcing: never UPDATE, only APPEND\nasync function debitAccount(accountId, amount, userId) {\n  const account = await replayAccountEvents(accountId);\n  if (account.balance &lt; amount)\n    throw new AppError('Insufficient funds', 400);\n\n  const event = {\n    id: crypto.randomUUID(), type: 'AccountDebited',\n    accountId, amount, userId, occurredAt: new Date()\n  };\n  await eventStore.append(event); // never update, only append!\n  return event;\n}\n\nasync function replayAccountEvents(accountId) {\n  const events = await eventStore.loadEvents(accountId);\n  return events.reduce((state, event) => {\n    switch (event.type) {\n      case 'AccountOpened':   return { ...state, balance: 0 };\n      case 'AccountDebited':  return { ...state, balance: state.balance - event.amount };\n      case 'AccountCredited': return { ...state, balance: state.balance + event.amount };\n      default: return state;\n    }\n  }, { balance: 0 });\n}", "explain": "\"Event sourcing is the natural model for financial systems and any domain where audit trails are legally required. Banks effectively already do event sourcing — your bank statement is the list of transactions, not just a current balance. The performance challenge: replaying thousands of events on every read is slow. The solution is snapshots — periodically save current state alongside the event log, then replay only events after the latest snapshot.\"", "tip": "Event sourcing combined with CQRS uses separate models: the command side appends events and enforces business rules, while the read side maintains denormalized query tables optimized for display. This enables read models to be rebuilt at any time by replaying all historical events." },
{ "id": 44, "cat": "Server Management", "tech": ["DevOps", "Observability"], "diff": "Hard", "q": "How do you implement distributed tracing in a microservices architecture?", "a": "<strong>Distributed tracing</strong> tracks a request as it flows through multiple services, providing an end-to-end view of performance and failures. Without it, debugging a slow request in microservices is nearly impossible — you do not know which of the 10 services in the call chain is slow.<br><br>Core concepts:<br><strong>Trace</strong>: The complete journey of a request across all services.<br><strong>Span</strong>: A single unit of work within a trace (one service's operation, one DB query).<br><strong>Trace ID</strong>: A UUID propagated through all service calls to correlate spans.<br><strong>OpenTelemetry</strong>: The vendor-neutral standard for instrumentation — exports to Jaeger, Zipkin, Datadog, Honeycomb.", "code": "// OpenTelemetry in Node.js -- auto-instrumentation\nimport { NodeSDK } from '@opentelemetry/sdk-node';\nimport { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';\nimport { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node';\n\nconst sdk = new NodeSDK({\n  serviceName:   'order-service',\n  traceExporter: new OTLPTraceExporter({ url: 'http://otel:4318/v1/traces' }),\n  instrumentations: [getNodeAutoInstrumentations()], // auto Express, pg, redis!\n});\nsdk.start();\n\n// Custom span for business logic\nimport { trace, SpanStatusCode } from '@opentelemetry/api';\nconst tracer = trace.getTracer('order-service');\n\nasync function processOrder(orderId) {\n  const span = tracer.startSpan('processOrder');\n  span.setAttribute('order.id', orderId);\n  try {\n    const order = await db.findOrder(orderId);\n    span.setStatus({ code: SpanStatusCode.OK });\n    return order;\n  } catch (err) {\n    span.recordException(err);\n    span.setStatus({ code: SpanStatusCode.ERROR });\n    throw err;\n  } finally {\n    span.end(); // ALWAYS end spans!\n  }\n}", "explain": "\"Distributed tracing transformed how I debug microservices issues. When a user reports checkout is slow, I open Jaeger, find their trace ID, and immediately see exactly which service and which database query caused the delay. 10 minutes to isolate a problem that would take hours of log searching across multiple services. OpenTelemetry auto-instrumentation is remarkable — it instruments Express routes, database queries, and HTTP requests with zero code changes.\"", "tip": "Sample traces intelligently in high-traffic production systems — 100% sampling at scale is expensive. Always record traces with errors or high latency. Sample randomly at 1-5% for normal traces. Also alert on trace-based SLOs: if P95 latency for a critical span exceeds a threshold, page the on-call engineer." },
{ "id": 45, "cat": "Architecture", "tech": ["Architecture"], "diff": "Expert", "q": "What is the CAP theorem and how does it influence database and system design decisions?", "a": "The <strong>CAP theorem</strong> states that in a distributed system, it is impossible to simultaneously guarantee all three: <strong>Consistency</strong> (every read receives the most recent write), <strong>Availability</strong> (every request gets a non-error response), and <strong>Partition Tolerance</strong> (the system continues despite network failures between nodes).<br><br>Network partitions are not optional in distributed systems — so partition tolerance is non-negotiable. The real choice is: when a partition occurs, do you prioritize Consistency (refuse to answer rather than risk stale data) or Availability (answer with possibly stale data)?<br><br><strong>CP systems</strong>: ZooKeeper, MongoDB with majority write concern. <strong>AP systems</strong>: DynamoDB, Cassandra (default), DNS.", "code": "// CP choice: strict consistency, might reject during partition\nawait collection.insertOne(payment, {\n  writeConcern: { w: 'majority', j: true }\n});\n// If primary cannot reach a majority during a partition, this BLOCKS\n// Prioritizes: correct data over availability\n\n// AP choice: always responds, data might be slightly stale\nconst result = await dynamodb.get({\n  TableName: 'Users', Key: { userId: '123' },\n  ConsistentRead: false  // fast, but might be a few seconds stale\n}).promise();\n// Prioritizes: availability over strict consistency\n\n// Decision framework:\n// Financial balance check  -> CP (wrong balance = fraud risk)\n// Social media feed        -> AP (2-second-old feed is fine)\n// Shopping cart total      -> CP (wrong total = wrong charge)", "explain": "\"CAP theorem is foundational for database selection. I explain it with a partition scenario: a primary and replica database have their network connection fail. CP choice: stop accepting reads from the replica — users get errors but data is always correct. AP choice: keep serving reads — users get answers but possibly stale ones. For banking, choose CP every time. For a social media feed, AP is perfectly fine.\"", "tip": "The PACELC model extends CAP beyond partition scenarios. Even during normal operation, every distributed system must trade off Latency versus Consistency: read from the nearest node (low latency, possibly stale) or the authoritative primary (correct data, higher latency)? Most practical database decisions are really PACELC decisions, not pure CAP decisions." },
{ "id": 46, "cat": "Databases", "tech": ["PostgreSQL"], "diff": "Expert", "q": "What is MVCC in PostgreSQL and how does it affect vacuum, bloat, and performance?", "a": "<strong>MVCC (Multi-Version Concurrency Control)</strong> is PostgreSQL's mechanism for concurrent access without blocking. Instead of locking rows on update or delete, PostgreSQL creates a new version of the row alongside the old one. Readers never block writers and writers never block readers.<br><br>The consequence: dead tuples accumulate. When a transaction updates or deletes a row, the old version becomes a dead tuple — logically deleted but still physically present. Over time, dead tuples cause <strong>table bloat</strong> — tables grow larger than the live data they contain.<br><br><strong>VACUUM</strong> reclaims space from dead tuples. <strong>AUTOVACUUM</strong> runs this automatically. <strong>VACUUM FULL</strong> rewrites the table completely but locks it exclusively.", "code": "-- Check table bloat\nSELECT tablename,\n  pg_size_pretty(pg_total_relation_size(schemaname||'.'||tablename)) AS size,\n  n_live_tup, n_dead_tup,\n  ROUND(100.0 * n_dead_tup / NULLIF(n_live_tup + n_dead_tup, 0), 2) AS dead_pct\nFROM pg_stat_user_tables\nORDER BY n_dead_tup DESC;\n\n-- Manual vacuum (non-blocking)\nVACUUM ANALYZE orders;\n-- VACUUM FULL orders; -- avoid! Locks table. Use pg_repack instead.\n\n-- Tune autovacuum for a high-churn table\nALTER TABLE orders SET (\n  autovacuum_vacuum_scale_factor = 0.01,  -- trigger at 1% dead (default 20%)\n  autovacuum_vacuum_cost_delay   = 2      -- less IO throttling\n);\n\n-- Check Transaction ID Wraparound (catastrophic if ignored!)\nSELECT datname, age(datfrozenxid) AS xid_age\nFROM pg_database ORDER BY age(datfrozenxid) DESC;", "explain": "\"MVCC is why PostgreSQL has excellent concurrent read/write performance — readers never wait for writers. The operational cost is vacuum. On write-heavy tables like orders or events, default autovacuum settings are often too conservative. I tune autovacuum_vacuum_scale_factor down to 0.01 so vacuum triggers at 1% dead tuples instead of the default 20%. For severe bloat, pg_repack rebuilds the table online without an exclusive lock, unlike VACUUM FULL.\"", "tip": "Transaction ID wraparound is a catastrophic, silent failure mode. After approximately 2 billion transactions, PostgreSQL refuses to start accepting new transactions to prevent data corruption. Monitor xid_age and alert if it approaches 1.5 billion. Autovacuum prevents this by freezing old transactions, but must not be allowed to fall behind on busy tables." },
{ "id": 47, "cat": "Node.js", "tech": ["Node.js", "Architecture"], "diff": "Expert", "q": "How do you design a distributed rate-limiting system that works correctly across many Node.js instances?", "a": "Single-server rate limiting using in-memory counters breaks in distributed deployments because each server instance maintains independent counters. A user making 90 requests round-robined across 3 servers sees each server allow 30 — the limit of 100 is effectively never enforced.<br><br>Distributed rate limiting requires a shared, atomic data store. The most robust implementation uses a <strong>Lua script</strong> in Redis — the entire check-and-update runs as a single indivisible atomic operation, preventing race conditions even with thousands of simultaneous requests.", "code": "// Token Bucket in Redis with Lua -- atomic, no race conditions\nconst rateLimit = async (redis, key, ratePerSec, burstCapacity) => {\n  const lua = `\n    local tokens_key = KEYS[1]\n    local ts_key     = KEYS[2]\n    local rate       = tonumber(ARGV[1])\n    local capacity   = tonumber(ARGV[2])\n    local now        = tonumber(ARGV[3])\n\n    local last_tokens    = tonumber(redis.call('get', tokens_key)) or capacity\n    local last_refreshed = tonumber(redis.call('get', ts_key))     or 0\n    local elapsed = math.max(0, now - last_refreshed)\n    local filled  = math.min(capacity, last_tokens + (elapsed/1000) * rate)\n    local allowed = filled &gt;= 1\n    local newt    = allowed and (filled - 1) or filled\n    local ttl     = math.ceil(capacity / rate) + 1\n\n    redis.call('setex', tokens_key, ttl, newt)\n    redis.call('setex', ts_key, ttl, now)\n    return allowed and 1 or 0\n  `;\n  return (await redis.eval(lua, {\n    keys: [`rl:t:${key}`, `rl:ts:${key}`],\n    arguments: [String(ratePerSec), String(burstCapacity), String(Date.now())]\n  })) === 1;\n};\n\napp.use('/api', async (req, res, next) => {\n  const allowed = await rateLimit(redis, req.user?.id || req.ip, 10, 50);\n  if (!allowed) return res.status(429).json({ error: 'Rate limit exceeded' });\n  next();\n});", "explain": "\"Distributed rate limiting with Lua scripts is the production standard at scale. The key insight: Lua scripts in Redis execute atomically — the entire read-check-write sequence runs as a single operation, so there are no race conditions even with hundreds of simultaneous requests. The token bucket algorithm allows controlled bursting while still enforcing a sustainable long-term rate.\"", "tip": "Redis cluster mode introduces complexity because keys on different cluster nodes cannot be operated atomically together. Use hash tags to force co-location: prefix keys with {user:123} so both {user:123}:tokens and {user:123}:ts land on the same Redis cluster shard." },
{ "id": 48, "cat": "Architecture", "tech": ["Architecture", "Databases"], "diff": "Expert", "q": "What is CQRS and event sourcing and when would you use them together?", "a": "<strong>CQRS (Command Query Responsibility Segregation)</strong> separates a system's write model (commands) from its read model (queries). Instead of one unified model, you maintain two separately optimized models.<br><br><strong>Write model</strong>: Accepts commands, validates business rules, applies changes. Optimized for integrity.<br><strong>Read model</strong>: Serves reads from denormalized, pre-joined query tables. Can use entirely different database technology.<br><br>Combined with event sourcing, every domain event updates one or more read models asynchronously — the event log is the source of truth, and read models are projections that can be rebuilt at any time by replaying events.", "code": "// COMMAND SIDE: business rules, append events\nasync function placeOrder(customerId, items) {\n  const customer = await replayCustomerEvents(customerId);\n  if (!customer.isActive) throw new Error('Account suspended');\n\n  const events = [\n    { type: 'OrderPlaced', customerId, items, total: calcTotal(items) },\n    { type: 'InventoryReserved', items }\n  ];\n  await eventStore.appendAll(events);\n  return events;\n}\n\n// READ MODEL PROJECTION: subscribe to events, update query table\neventBus.on('OrderPlaced', async (event) => {\n  await db.query(`\n    INSERT INTO order_dashboard_view (order_id, total, status, created_at)\n    VALUES ($1, $2, 'placed', NOW())\n  `, [event.orderId, event.total]);\n});\n\n// READ SIDE: instant, no runtime JOINs needed!\nasync function getDashboardOrders(filter) {\n  return db.query('SELECT * FROM order_dashboard_view WHERE status = $1', [filter.status]);\n}", "explain": "\"CQRS and event sourcing together are right for domains with complex business rules, audit requirements, and dramatically different read and write needs. The combination gives you an immutable audit trail, the ability to add new read models anytime by replaying events, and independently scalable read and write sides. The cost is significant complexity — use this only when simpler approaches genuinely cannot meet requirements.\"", "tip": "When adding a new read model in CQRS with event sourcing, you rebuild it from scratch by replaying all historical events through the new projection. This is a superpower — add a new dashboard view today and retroactively populate it with all historical data without any data migration." },
{ "id": 49, "cat": "Server Management", "tech": ["DevOps", "Server"], "diff": "Expert", "q": "How do you implement zero-downtime deployments for a stateful backend application?", "a": "Zero-downtime deployment ensures users never experience outages during updates.<br><br><strong>Rolling deployment</strong>: Update instances one at a time. Requires old and new versions to be backward-compatible.<br><br><strong>Blue-Green deployment</strong>: Two identical environments. Deploy to green, validate, then atomically switch traffic. Instant rollback by switching back.<br><br><strong>Canary deployment</strong>: Route a small percentage of traffic (1-5%) to the new version, monitor error rates, gradually increase if healthy.", "code": "# Rolling deployment with PM2 -- zero dropped connections\npm2 reload api --update-env\n# Each worker: stops accepting new connections,\n# finishes in-flight requests, restarts with new code\n\n# Blue-Green switch with Nginx\nsed -i 's/proxy_pass http:\\/\\/blue/proxy_pass http:\\/\\/green/' \\\n    /etc/nginx/conf.d/app.conf\nnginx -s reload   # graceful -- no dropped connections!\n\n# Database migration: never break this rule!\n# Deploy order for adding a column:\n# 1. Add column as nullable (old code works, ignores it)\n# 2. Deploy new code that writes to new column too\n# 3. Backfill old data to new column\n# 4. Deploy code that reads only new column\n# 5. Add NOT NULL constraint\n# 6. Remove old column in a later deploy", "explain": "\"Zero-downtime deployment requires thinking about both the application tier and the database tier together. The most common mistake: adding a NOT NULL column in the same deploy that introduces code expecting it — old running instances fail with constraint violations. The Expand-Contract pattern solves this across multiple separate deployments.\"", "tip": "Implement a readiness probe distinct from a liveness probe. Liveness tells the load balancer whether the process is running. Readiness tells it whether the new instance is fully ready — connection pool warmed up, caches populated. Route traffic only after readiness passes." },
{ "id": 50, "cat": "Architecture", "tech": ["Architecture", "Node.js"], "diff": "Expert", "q": "What is the saga pattern and how does it manage distributed transactions across microservices?", "a": "A business operation may span multiple microservices, each with its own database. Traditional ACID transactions cannot span service boundaries.<br><br>The <strong>Saga pattern</strong> manages distributed transactions as a sequence of local transactions, each publishing an event that triggers the next step. If any step fails, compensating transactions undo the previous steps in reverse order.<br><br><strong>Choreography</strong>: Each service listens for events and reacts — decentralized, hard to visualize at scale.<br><strong>Orchestration</strong>: A central orchestrator explicitly tells each service what to do — easier to debug, state tracked persistently.", "code": "// Orchestration saga -- Order placement across 3 services\nclass OrderPlacementSaga {\n  async execute(orderData) {\n    let orderId, inventoryReserved = false, paymentId;\n    try {\n      orderId = await orderService.create(orderData);\n      await inventoryService.reserve(orderData.items);\n      inventoryReserved = true;\n      paymentId = await paymentService.charge(orderData.payment);\n      await orderService.confirm(orderId);\n    } catch (error) {\n      // Compensating transactions -- undo in REVERSE order\n      if (paymentId)         await paymentService.refund(paymentId);\n      if (inventoryReserved) await inventoryService.release(orderData.items);\n      if (orderId)           await orderService.cancel(orderId);\n      throw new Error('Order failed -- all steps reversed');\n    }\n  }\n}", "explain": "\"Sagas replace the distributed ACID transaction with a sequence of eventually consistent local transactions. Instead of requiring all services available simultaneously for a two-phase commit, we accept temporary inconsistency with the guarantee of eventual consistency — either everything succeeds or compensation brings us back to a clean state. Orchestration sagas store their state persistently — if the orchestrator crashes mid-saga, it resumes or compensates on restart.\"", "tip": "Idempotency is absolutely critical for saga steps. If a step is retried after a partial failure, re-executing it should produce the same result, not a duplicate charge. Use idempotency keys when calling external services to prevent double-charging or double-processing." }
];


/* ── Constants ── */
const SK = 'iqhub_backend_v2';

/* ── Validated localStorage load ── */
function loadDone(key) {
  try {
    var raw = localStorage.getItem(key);
    if (!raw) return new Set();
    var parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return new Set();
    return new Set(parsed.filter(function(n) {
      return Number.isInteger(n) && n > 0 && n <= 200;
    }));
  } catch(e) { return new Set(); }
}

var done = loadDone(SK);
var fDiff = 'all';
var fCat  = 'all';

var cats = [...new Set(Q.map(function(q) { return q.cat; }))];

/* ── Category filter buttons ── */
function buildCatButtons() {
  var catbtns = document.getElementById('catbtns');
  if (!catbtns) return;
  catbtns.innerHTML = '';

  var allBtn = document.createElement('button');
  allBtn.className = 'btn';
  allBtn.setAttribute('aria-pressed', 'true');
  allBtn.textContent = 'All';
  allBtn.addEventListener('click', function() { setC('all', allBtn); });
  catbtns.appendChild(allBtn);

  cats.forEach(function(c) {
    var b = document.createElement('button');
    b.className = 'btn';
    b.setAttribute('aria-pressed', 'false');
    b.textContent = c;
    b.addEventListener('click', function() { setC(c, b); });
    catbtns.appendChild(b);
  });
}

function setC(c, btn) {
  fCat = c;
  var catbtns = document.getElementById('catbtns');
  if (catbtns) {
    catbtns.querySelectorAll('.btn').forEach(function(b) {
      b.setAttribute('aria-pressed', b === btn ? 'true' : 'false');
    });
  }
  render();
}

/* ── Difficulty buttons ── */
function initDiffButtons() {
  document.querySelectorAll('[data-d]').forEach(function(b) {
    b.addEventListener('click', function() {
      document.querySelectorAll('[data-d]').forEach(function(x) {
        x.setAttribute('aria-pressed', 'false');
        x.classList.remove('e', 'm');
      });
      b.setAttribute('aria-pressed', 'true');
      var v = b.dataset.d;
      fDiff = v;
      if (v === 'Easy') b.classList.add('e');
      else if (v === 'Medium') b.classList.add('m');
      render();
    });
  });
}

/* ── Toggle accordion ── */
function tog(id) {
  var body   = document.getElementById('b' + id);
  var togBtn = document.getElementById('tb' + id);
  var card   = document.getElementById('c' + id);
  if (!body || !togBtn || !card) return;
  var isOpen = !body.hidden;
  body.hidden = isOpen;
  togBtn.setAttribute('aria-expanded', String(!isOpen));
  card.classList.toggle('open', !isOpen);
  if (!isOpen) {
    // announce for screen readers
    announce('Answer expanded');
  }
}

/* ── Mark done ── */
function mkDone(id) {
  var btn  = document.getElementById('db' + id);
  var card = document.getElementById('c' + id);
  if (!btn || !card) return;
  var isDone = done.has(id);
  if (isDone) {
    done.delete(id);
    btn.setAttribute('aria-pressed', 'false');
    btn.setAttribute('aria-label', 'Mark question ' + id + ' as done');
    card.classList.remove('done');
    announce('Marked as not done');
  } else {
    done.add(id);
    btn.setAttribute('aria-pressed', 'true');
    btn.setAttribute('aria-label', 'Question ' + id + ' marked as done. Click to undo.');
    card.classList.add('done');
    announce('Marked as done');
  }
  try { localStorage.setItem(SK, JSON.stringify([...done])); } catch(ex) {}
  upd();
}

/* ── Accessible live announcer ── */
function announce(msg) {
  var live = document.getElementById('a11y-live');
  if (!live) return;
  live.textContent = '';
  setTimeout(function() { live.textContent = msg; }, 50);
}

/* ── Escape HTML (for any future user-dynamic content) ── */
function escapeHTML(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/* ── Render question list ── */
function render() {
  // Search is filtered, never written to DOM
  var srchEl = document.getElementById('srch');
  var s = srchEl ? srchEl.value.toLowerCase().trim().slice(0, 120) : '';

  var list = document.getElementById('ql');
  if (!list) return;
  list.innerHTML = '';

  var fil = Q.filter(function(q) {
    var d  = fDiff === 'all' || q.diff === fDiff;
    var c  = fCat  === 'all' || q.cat  === fCat;
    var sr = !s ||
      q.q.toLowerCase().includes(s) ||
      q.cat.toLowerCase().includes(s) ||
      q.tech.some(function(t) { return t.toLowerCase().includes(s); });
    return d && c && sr;
  });

  if (!fil.length) {
    var emp = document.createElement('div');
    emp.className = 'es';
    emp.setAttribute('role', 'status');
    emp.innerHTML = '<p>No questions match. Try adjusting filters or search.</p>';
    list.appendChild(emp);
    upd();
    return;
  }

  fil.forEach(function(q) {
    var isDone = done.has(q.id);
    var article = document.createElement('article');
    article.className = 'qc' + (isDone ? ' done' : '');
    article.id = 'c' + q.id;

    var tagsHTML = q.tech.map(function(t) {
      return '<span class="tg tt">' + escapeHTML(t) + '</span>';
    }).join('') +
    '<span class="tg t' + escapeHTML(q.diff.toLowerCase().charAt(0)) + '">' + escapeHTML(q.diff) + '</span>' +
    '<span class="tg tc">' + escapeHTML(q.cat) + '</span>';

    var codeHTML = q.code
      ? '<div class="cb" role="region" aria-label="Code example"><code>' + q.code + '</code></div>'
      : '';

    // NOTE: q.a, q.explain, q.tip are from a trusted, hardcoded array — not user input.
    // q.q (question text) is also hardcoded; escapeHTML applied to dynamic parts only.
    article.innerHTML =
      '<div class="qh">' +
        '<span class="qn" aria-hidden="true">' + String(q.id).padStart(2, '0') + '</span>' +
        '<div class="qm">' +
          '<div class="qt" aria-label="Tags">' + tagsHTML + '</div>' +
          '<p class="qq" id="qq' + q.id + '">' + q.q + '</p>' +
        '</div>' +
        '<div class="qa">' +
          '<button class="db' + (isDone ? ' done' : '') + '"' +
            ' id="db' + q.id + '"' +
            ' aria-pressed="' + (isDone ? 'true' : 'false') + '"' +
            ' aria-label="' + (isDone ? 'Question ' + q.id + ' done. Click to undo' : 'Mark question ' + q.id + ' as done') + '"' +
            ' data-done-id="' + q.id + '">' +
            '<svg viewBox="0 0 24 24" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg>' +
          '</button>' +
          '<button class="toggle-btn"' +
            ' id="tb' + q.id + '"' +
            ' aria-expanded="false"' +
            ' aria-controls="b' + q.id + '"' +
            ' aria-labelledby="qq' + q.id + '"' +
            ' data-toggle-id="' + q.id + '">' +
            '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" aria-hidden="true"><polyline points="6 9 12 15 18 9"/></svg>' +
            '<span class="sr-only">Toggle answer</span>' +
          '</button>' +
        '</div>' +
      '</div>' +
      '<div class="qb" id="b' + q.id + '" role="region" aria-labelledby="qq' + q.id + '" hidden>' +
        '<div class="sh" aria-hidden="true">Answer</div>' +
        '<div class="at">' + q.a + '</div>' +
        codeHTML +
        '<div class="eb">' +
          '<div class="ehe" aria-hidden="true">How to explain it to the interviewer</div>' +
          '<p class="et">' + q.explain + '</p>' +
        '</div>' +
        '<div class="tb"><div class="tbl" aria-hidden="true">Pro Tip</div><p>' + q.tip + '</p></div>' +
      '</div>';

    list.appendChild(article);
  });

  // Attach events AFTER insertion (not via inline handlers)
  fil.forEach(function(q) {
    var togBtn = document.getElementById('tb' + q.id);
    var doneBtn = document.getElementById('db' + q.id);
    if (togBtn) togBtn.addEventListener('click', function() { tog(q.id); });
    if (doneBtn) doneBtn.addEventListener('click', function(e) { e.stopPropagation(); mkDone(q.id); });
  });

  upd();
}

/* ── Keyboard: Escape closes open accordion ── */
function initKeyboard() {
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
      document.querySelectorAll('.toggle-btn[aria-expanded="true"]').forEach(function(btn) {
        var id = btn.dataset.toggleId;
        if (id) tog(parseInt(id, 10));
      });
    }
  });
}

/* ── Update stats ── */
function upd() {
  var tot = Q.length;
  var dn  = done.size;
  var pct = tot > 0 ? Math.round((dn / tot) * 100) : 0;

  var setTxt = function(id, val) {
    var el = document.getElementById(id);
    if (el) el.textContent = val;
  };
  setTxt('tQ', tot);
  setTxt('dQ', dn);
  setTxt('lQ', tot - dn);
  setTxt('pQ', pct + '%');
  setTxt('ptxt', dn + ' / ' + tot + ' completed');

  var pfill = document.getElementById('pfill');
  if (pfill) pfill.style.width = pct + '%';

  var statsRegion = document.getElementById('stats-region');
  if (statsRegion) statsRegion.setAttribute('aria-label', dn + ' of ' + tot + ' questions completed, ' + pct + ' percent');

  var cpwrap = document.getElementById('cpwrap');
  if (cpwrap) {
    cpwrap.innerHTML = '';
    cats.forEach(function(c) {
      var ct = Q.filter(function(q) { return q.cat === c; }).length;
      var cd = Q.filter(function(q) { return q.cat === c && done.has(q.id); }).length;
      var p  = document.createElement('div');
      p.className = 'cpill';
      // c comes from Q array (trusted), cd/ct are integers — safe
      p.innerHTML = '<span class="dot" aria-hidden="true"></span>' + escapeHTML(c) + ': ' + cd + '/' + ct;
      cpwrap.appendChild(p);
    });
  }
}

/* ── Search: debounced ── */
function debounce(fn, delay) {
  var timer;
  return function() {
    clearTimeout(timer);
    timer = setTimeout(fn, delay);
  };
}

/* ── Init ── */
document.addEventListener('DOMContentLoaded', function() {
  buildCatButtons();
  initDiffButtons();
  initKeyboard();
  document.getElementById('srch') && document.getElementById('srch').addEventListener('input', debounce(render, 200));
  render();
});
